import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
const _not_found = {title: "Unknown", jsx: <><h2 id="discovery-not_found-unknown">Unknown</h2>
<p>Unable to find the requested alchemist discovery.</p>
</>};
const _acid_bomb = {title: "Acid Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-acid_bomb-acid-bomb">Acid Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>When the alchemist creates a bomb, he can choose to have it inflict acid damage. Creatures that take a direct hit from an acid bomb take an additional 1d6 points of acid damage 1 round later.</p>
</>};
const _anarchic_bombs = {title: "Anarchic Bombs", addenda: ["primarybomb"], jsx: <><h2 id="discovery-anarchic_bombs-anarchic-bombs">Anarchic Bombs</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-anarchic_bombs--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it deal chaotic divine damage. Lawful creatures that take a direct hit from an anarchic bomb must succeed at a Fortitude save or be <Link to="/misc/staggered">staggered</Link> on their next turn. Against neutral creatures, anarchic bombs deal half damage, and such targets are not affected by their staggering effect. Anarchic bombs have no effect on chaotic-aligned creatures.</p>
</>};
const _anguish_bomb = {title: "Anguish Bomb", addenda: ["primarybomb"], tree: ["Dread Bomb","Melancholy Bomb"], jsx: <><h2 id="discovery-anguish_bomb-anguish-bomb">Anguish Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms</Link><br/>You can throw bombs infused with psychic trauma. This discovery allows other alchemists to duplicate the anguish bombs used by <Link to="/arc-alchemist/mnemostiller">mnemostillers</Link>.</p>
</>};
const _dread_bomb = {title: "Dread Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-dread_bomb-dread-bomb">Dread Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-dread_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>6th level alchemist</li><li><strong>Class Feature or Discovery:</strong> <Link to="/discovery/anguish_bomb">anguish bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>Your anguish bombs are tainted with fear and dread. Creatures who take damage from your anguish bombs become <Link to="/misc/frightened">frightened</Link> for 1d6 rounds. A target that succeeds at a Will saving throw is instead <Link to="/misc/shaken">shaken</Link> for a single round.</p>
</>};
const _melancholy_bomb = {title: "Melancholy Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-melancholy_bomb-melancholy-bomb">Melancholy Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-melancholy_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>10th level alchemist</li><li><strong>Class Feature or Discovery:</strong> <Link to="/discovery/anguish_bomb">anguish bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>Your anguish bombs are filled with memories of sadness and regret. Creatures who take damage from your anguish bombs are also affected as per <Link to="/spell/crushing_despair">crushing despair</Link> for 1 round per alchemist level, or a single round if the target succeeds at a Will saving throw.</p>
</>};
const _axiomatic_bombs = {title: "Axiomatic Bombs", addenda: ["primarybomb"], jsx: <><h2 id="discovery-axiomatic_bombs-axiomatic-bombs">Axiomatic Bombs</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-axiomatic_bombs--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it deal lawful divine damage. Chaotic creatures that take a direct hit from an axiomatic bomb must succeed at a Fortitude save or be <Link to="/misc/staggered">staggered</Link> on their next turn. Against neutral creatures, axiomatic bombs deal half damage, and such targets are not affected by their staggering effect. Axiomatic bombs have no effect on lawful creatures.</p>
</>};
const _blinding_bomb = {title: "Blinding Bomb", addenda: ["primarybomb"], tree: ["Sunlight bomb"], jsx: <><h2 id="discovery-blinding_bomb-blinding-bomb">Blinding Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-blinding_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose for it to detonate very brightly. Creatures that take a direct hit from a blinding bomb are <Link to="/misc/blinded">blinded</Link> for 1 minute unless they succeed at a Fortitude save. Creatures in the splash area that fail their saves against the bomb are <Link to="/misc/dazzled">dazzled</Link> for 1 minute. This is a light effect.</p>
</>};
const _sunlight_bomb = {title: "Sunlight Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-sunlight_bomb-sunlight-bomb">Sunlight Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-sunlight_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>10th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/blinding_bomb">blinding bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist can throw bombs that explode with a searing radiance equivalent to that of sunlight and that act as blinding bombs. Undead, fungi, molds, oozes, slimes, and creatures to which sunlight is harmful or unnatural take +2 damage per die from the bomb. Undead that are harmed by sunlight and that fail their saves against the bomb are <Link to="/misc/staggered">staggered</Link> for 1 round.</p>
</>};
const _boneshard_bomb = {title: "Boneshard Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-boneshard_bomb-boneshard-bomb">Boneshard Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-boneshard_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/alchemical_zombie">alchemical zombie</Link></td></tr></tbody></table></ScrollContainer></div><p>This discovery is popular among necromancers and necrologists alike; aside from its offensive potential, necrologists sometimes use it to turn uncooperative live creatures they wish to question into pliable undead. The alchemist's bomb deals piercing damage instead of fire damage, and creatures that take a direct hit from a boneshard bomb must succeed at a Fortitude save or take 1d4 points of <Link to="/rule/bleed">bleed</Link> damage in addition to normal damage. If a creature is killed by a boneshard bomb or the resulting bleed effect, its corpse immediately reanimates as an undead creature with the <Link to="/template/skeleton">skeleton template</Link>. Skeletons that are created in this manner count as undead created by <Link to="/spell/animate_dead">animate dead</Link> for the purposes of determining how many undead the alchemist can control.</p>
</>};
const _breath_weapon_bomb = {title: "Breath Weapon Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-breath_weapon_bomb-breath-weapon-bomb">Breath Weapon Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-breath_weapon_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Instead of drawing the components of, creating, and throwing a bomb, the alchemist can draw the components, drink them, mix them within his body, and then expel them as a breath weapon as a standard action. This breath weapon is a 15-foot cone and has the same DC as the bomb. Each creature within the cone takes damage as if it had suffered a direct hit from the alchemist's bomb, but succeeding at a Reflex save (DC = 10 + 1/2 the alchemist's level + the alchemist's Intelligent modifier) halves the damage. Unlike throwing normal bombs, drawing, drinking, and expelling breath weapon bombs does not provoke attacks of opportunity.</p>
</>};
const _concussive_bomb = {title: "Concussive Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-concussive_bomb-concussive-bomb">Concussive Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-concussive_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it inflict sonic damage. Concussive bombs deal 1d4 points of sonic damage, plus 1d4 points of sonic damage for every odd-numbered level, instead of 1d6. Creatures that take a direct hit from a concussive bomb are <Link to="/misc/deafened">deafened</Link> for 1 minute unless they succeed at a Fortitude save.</p>
</>};
const _confusion_bomb = {title: "Confusion Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-confusion_bomb-confusion-bomb">Confusion Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-confusion_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist's bombs twist the target's perception of friend and foe. A creature that takes a direct hit from a confusion bomb takes damage from the bomb and is under the effect of a <Link to="/spell/confusion">confusion</Link> spell for 1 round per caster level of the alchemist. Reduce the amount of normal damage dealt by the bomb by 2d6 (so a bomb that would normally deal 6d6+4 points of damage deals 4d6+4 points of damage instead).</p>
</>};
const _cursed_bomb = {title: "Cursed Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-cursed_bomb-cursed-bomb">Cursed Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-cursed_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>12th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When an alchemist creates a bomb, he can choose to have it deliver a debilitating curse. A creature that takes a direct hit from a cursed bomb must succeed at a Will save or be affected by <Link to="/spell/bestow_curse">bestow curse</Link>.</p>
</>};
const _cytillesh_bomb = {title: "Cytillesh Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-cytillesh_bomb-cytillesh-bomb">Cytillesh Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex</Link><br/>When the alchemist creates a bomb, he can infuse it with <Link to="/eq-poison/cytillesh_extract">cytillesh extract</Link>. Cytillesh bombs deal 1d4 points of damage, plus 1d4 points of damage for every odd-numbered level, instead of 1d6. Creatures that take a direct hit from a cytillesh bomb are <Link to="/misc/sickened">sickened</Link> for 1 round per alchemist level unless they succeed at Fortitude saves. If a creature is rendered unconscious from this bomb or any other attack before it is able to remove the sickened condition, the victim loses all memory from the last hour and cannot form new memories for 8 hours. The lost and prevented memories might return later as dreams, and can be restored with a <Link to="/spell/restoration">restoration</Link> spell.</p>
</>};
const _darkness_bomb = {title: "Darkness Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-darkness_bomb-darkness-bomb">Darkness Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>When the alchemist creates a bomb, he can choose to have it suppress light sources on the target. This extinguishes nonmagical light sources carried by the target and dispels magical light sources for 1 round/level as <Link to="/spell/deeper_darkness">deeper darkness</Link>.</p>
</>};
const _defoliant_bomb = {title: "Defoliant Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-defoliant_bomb-defoliant-bomb">Defoliant Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>These poisonous bombs clear away foliage, dealing extra damage to plant creatures. When the alchemist creates a bomb, he can choose to have it deal extra damage against plant creatures but less damage against other creatures. Against creatures with the plant type, a defoliant bomb deals 1d8 points of damage, plus 1d8 points of damage for every odd-numbered level the alchemist possesses, instead of 1d6. Against all other creatures, the defoliant bomb only deals 1d4 points of damage, plus 1d4 points of damage for every odd-numbered level, instead of 1d6. This is a poison effect. A defoliant bomb kills all normal vegetation in the target's square and its splash area; any plant-based <Link to="/rule/difficult_terrain">difficult terrain</Link> in the affected area becomes normal terrain.</p>
</>};
const _demolition_charge = {title: "Demolition Charge", addenda: ["primarybomb"], jsx: <><h2 id="discovery-demolition_charge-demolition-charge">Demolition Charge</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-demolition_charge--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it deal damage to an object as if by a <Link to="/rule/sunder">sunder</Link> combat maneuver. If the item is worn or held by an opponent, the item is considered the direct target, and the wearer/holder takes splash damage from the blast. If the object is unattended, a demolition charge deals an additional 2d6 points of damage on a direct hit. This bonus doesn't affect the bomb's splash damage.</p>
</>};
const _ectoplasmic_bomb = {title: "Ectoplasmic Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-ectoplasmic_bomb-ectoplasmic-bomb">Ectoplasmic Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>The alchemist can infuse her bombs with a special unction that damages incorporeal creatures and reveals the presence of undead creatures hiding in the area. Incorporeal creatures struck by an ectoplasmic bomb take full damage from the bomb. In addition, squares in the affected area of the bomb begin to faintly glow in the spaces where undead creatures have traveled in the last minute, including undead benefiting from <Link to="/spell/invisibility">invisibility</Link> or other forms of obscurity (such as <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>), effectively creating a glowing trail. Any undead creatures in the affected area at the time of the explosion likewise glow faintly. This glowing effect lasts for 1 minute, and is otherwise identical to <Link to="/spell/faerie_fire">faerie fire</Link>.</p>
</>};
const _explosive_bomb = {title: "Explosive Bomb", addenda: ["primarybomb"], tree: ["Hellfire Bomb","Siege Bomb"], jsx: <><h2 id="discovery-explosive_bomb-explosive-bomb">Explosive Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The alchemist's bombs now have a splash radius of 10 feet rather than 5 feet. Creatures that take a direct hit from an explosive bomb catch fire, taking 1d6 points of fire damage each round until the fire is extinguished. Extinguishing the flames is a full-round action that requires a Reflex save. Rolling on the ground provides the target with a +2 to the save. Dousing the target with at least 2 gallons of water automatically extinguishes the flames.</p>
</>};
const _hellfire_bomb = {title: "Hellfire Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-hellfire_bomb-hellfire-bomb">Hellfire Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-hellfire_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>9th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/explosive_bomb">explosive bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>This discovery is available to <Link to="/race/tiefling">tiefling</Link> alchemists. When the alchemist creates a bomb, he can have it act as an explosive bomb, but deal half of its damage as fire damage and half as unholy damage that is not subject to fire resistance or immunity.</p>
</>};
const _siege_bomb = {title: "Siege Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-siege_bomb-siege-bomb">Siege Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-siege_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>12th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/explosive_bomb">explosive bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>As a standard action, the alchemist infuses a single piece of ammunition on a loaded siege weapon with the power of his bomb. As long as the siege engine with this ammunition is fired before the start of the alchemist's next turn, the ammunition does damage normally, and also deals the damage of the alchemist's bomb. The splash radius of the bomb effect is 20 feet rather than 5 feet. Creatures that take the bomb's damage (either direct damage or splash damage), take 1d6 points of fire damage each round until the fire is extinguished. Extinguishing the flames is a full-round action that requires a Reflex save. Rolling on the ground provides the target with a +2 bonus on the save. Dousing the target with at least 2 gallons of water automatically extinguishes the flames.</p>
</>};
const _flesh_eating_bomb = {title: "Flesh-Eating Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-flesh_eating_bomb-flesh-eating-bomb">Flesh-Eating Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook</Link><br/>The alchemist can create bombs that devour living matter. The alchemist's bomb deals damage one die step higher than normal (regular bombs deal d8s, concussive bombs (see below) deal 1d6, and so on), but they have no effect on inorganic matter. In addition, a creature with at least a +1 armor bonus to AC is less likely to be harmed; such creatures in the bomb's splash radius take no damage on a successful Reflex save, and the target of a direct hit can attempt a Reflex save against the bomb's save DC to take only half damage.</p>
<aside><p><strong>Note:</strong> Despite what the text seems to indicate, <Link to="/discovery/concussive_bomb">concussive bombs</Link> and flesh-eating bombs cannot be combined under the published rules. Consult your GM if you wish to use these two together.</p>
</aside></>};
const _force_bomb = {title: "Force Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-force_bomb-force-bomb">Force Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-force_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it inflict force damage. Force bombs deal 1d4 points of force damage, plus 1d4 points of force damage for every odd-numbered level, instead of 1d6. Creatures that take a direct hit from a force bomb are knocked <Link to="/rule/prone">prone</Link> unless they succeed on a Reflex save.</p>
</>};
const _frost_bomb = {title: "Frost Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-frost_bomb-frost-bomb">Frost Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>When the alchemist creates a bomb, he can choose to have it inflict cold damage. Creatures that take a direct hit from a frost bomb are <Link to="/misc/staggered">staggered</Link> on their next turn unless they succeed on a Fortitude save.</p>
</>};
const _glassfoot_bomb = {title: "Glassfoot Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-glassfoot_bomb-glassfoot-bomb">Glassfoot Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>When the alchemist creates a bomb, he can choose to have it cover the ground in volatile jagged crystals in addition to its normal effects. These crystals act like <Link to="/eq-misc/caltrops">caltrops</Link>, evaporating into a smelly but harmless gas in 2d6 rounds.</p>
</>};
const _grease_bomb = {title: "Grease Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-grease_bomb-grease-bomb">Grease Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-grease_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it create a grease slick upon detonation. When a grease bomb detonates, it coats an area equal to the bomb's splash radius in grease (as the <Link to="/spell/grease">grease</Link> spell) for 1 round per level. The DC of the Reflex save to avoid falling after a failed Acrobatics check is equal to 10 + 1/2 the alchemist's level + the alchemist's Intelligence modifier. A grease bomb can't affect items or armor.</p>
</>};
const _grounding_goo = {title: "Grounding Goo", addenda: ["primarybomb"], jsx: <><h2 id="discovery-grounding_goo-grounding-goo">Grounding Goo</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness</Link><br/>The alchemist's bomb applies a sticky residue after any damage from the bomb is resolved. If a creature damaged by the bomb has a nonmagical fly speed, its flight is severely impaired, and it takes a penalty equal to the alchemist's level on Fly checks for 1 minute.</p>
</>};
const _healing_bomb = {title: "Healing Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-healing_bomb-healing-bomb">Healing Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace</Link><br/>When the alchemist creates a bomb, he can choose to have it heal damage instead of dealing it. Creating a healing bomb requires the alchemist to expend an infused extract or potion containing a <Link to="/main/cure_spells">cure spell</Link>. A creature that takes a direct hit from a healing bomb is healed as if she had imbibed the infusion or potion used to create the bomb. Creatures in the splash radius are healed for the minimum amount of damage the cure spell is capable of healing. A healing bomb damages undead instead of healing them.</p>
</>};
const _holy_bombs = {title: "Holy Bombs", addenda: ["primarybomb"], jsx: <><h2 id="discovery-holy_bombs-holy-bombs">Holy Bombs</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-holy_bombs--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it deal good divine damage. Evil creatures that take a direct hit from a holy bomb must succeed at a Fortitude save or be <Link to="/misc/staggered">staggered</Link> on their next turn. Against neutral creatures, holy bombs deal half damage, and such targets are not affected by their staggering effect. Holy bombs have no effect on good-aligned creatures.</p>
</>};
const _immolation_bomb = {title: "Immolation Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-immolation_bomb-immolation-bomb">Immolation Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-immolation_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>3rd level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have its substance coat the direct target's body, causing the bomb to deal its damage over time instead of all at once. The bomb's effect lasts for a number of rounds equal to the number of damage dice the bomb would normally deal (for instance, a 5d6 bomb lasts for 5 rounds). When the bomb hits the direct target, the bomb deals 1d6 + the alchemist's Intelligence modifier in damage, and those within the splash zone take damage equal to 1 + the alchemist's Intelligence modifier. It repeats this damage against the direct target of the bomb each round the immolation bomb lasts, dealing the damage at the start of the alchemist's turn. Splash damage is dealt again to any creature that is adjacent to the direct target when it takes damage from the immolation bomb. A creature taking damage from an immolation bomb's direct hit can attempt to extinguish the flames as a full-round action that requires a Reflex save (DC = 10 + 1/2 the alchemist's level + the alchemist's Intelligent modifier). Because of the alchemical nature of this bomb, rolling on the ground does not grant a bonus on the saving throw, and dousing a creature with water does not stop it from burning. These bombs can be used underwater.</p>
</>};
const _incendiary_charge = {title: "Incendiary Charge", addenda: ["primarybomb"], jsx: <><h2 id="discovery-incendiary_charge-incendiary-charge">Incendiary Charge</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-incendiary_charge--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>An incendiary charge is a bomb specifically designed to overcome the effects of any nonmagical object's hardness. As a full-round action, the alchemist can place an incendiary charge that burns and eats away at an object, dealing normal bomb damage to it. (The damage is not halved against an object with hardness, unlike most energy damage.) Furthermore, the incendiary charge ignores the first 5 points of hardness of the material being damaged.</p>
</>};
const _jury_rigged_bomb = {title: "Jury-Rigged Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-jury_rigged_bomb-jury-rigged-bomb">Jury-Rigged Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-jury_rigged_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Unlike normal bombs, jury-rigged bombs can be created from whatever materials the alchemist has on hand; this makes them particularly handy in situations where the alchemist might find himself imprisoned or stripped of his equipment. Jury-rigged bombs can be crafted and thrown as a swift action (this counts against the alchemist's daily use of bombs), and they deal only 1d4 points of damage + additional damage equal to half the alchemist's Intelligence modifier on a direct hit. This damage increases by 1d4 at 3rd level and every 2 levels thereafter. Despite being useful in a pinch, jury-rigged bombs are nonetheless crudely crafted and highly unstable; if the alchemist's attack roll results in a natural 1, the bomb explodes as he is creating it, and he takes damage as if he had taken a direct hit.</p>
</>};
const _neutralizing_bomb = {title: "Neutralizing Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-neutralizing_bomb-neutralizing-bomb">Neutralizing Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>When the alchemist creates a bomb, he can choose to give it the potential to end certain ongoing effects instead of dealing damage. Each creature in the splash radius can attempt a new saving throw against any poison afflicting it and any ongoing conditions or ongoing acid, cold, electricity, fire, or sonic damage. (If an effect did not allow a saving throw, this bomb doesn't allow affected creatures to attempt one.) Success counts as one successful save toward ending poison and immediately ends other conditions. Exposed poison in the splash radius is also rendered harmless. A creature with poison abilities that is directly struck by the bomb finds those abilities useless for 1d4 rounds unless it succeeds at a Fortitude saving throw.</p>
</>};
const _ooze_blight = {title: "Ooze Blight", addenda: ["primarybomb"], jsx: <><h2 id="discovery-ooze_blight-ooze-blight">Ooze Blight</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook</Link><br/>A target hit by the alchemist's bomb loses the <Link to="/umr/split">split</Link> special quality for 1d4 rounds. In addition, against creatures with the ooze type, this bomb deals untyped damage that bypasses all resistances.</p>
</>};
const _penetrating_charge = {title: "Penetrating Charge", addenda: ["primarybomb"], jsx: <><h2 id="discovery-penetrating_charge-penetrating-charge">Penetrating Charge</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex</Link><br/>A penetrating charge is a bomb specifically designed to disable locks and similar mechanisms, though not other means of sealing a door, a container, or other sorts of devices. As a full-round action, the alchemist can place a penetrating charge on a lock. Instead of dealing damage, the penetrating charge seeps into the mechanism and eats away at it, granting a +5 circumstance bonus on any subsequent Disable Device checks against the mechanism. A creature can spend 10 minutes and attempt an appropriate Craft check (DC 15) to fix the lock and remove this bonus.</p>
</>};
const _poisoned_explosive = {title: "Poisoned Explosive", addenda: ["primarybomb"], jsx: <><h2 id="discovery-poisoned_explosive-poisoned-explosive">Poisoned Explosive</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-poisoned_explosive--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>4th level alchemist</li><li><Link to="/ability/poison_use">Poison use</Link> class feature</li></ul></td></tr></tbody></table></ScrollContainer></div><p>When an alchemist creates a bomb, he can apply a dose of contact or injury poison to it, as if applying poison to a weapon. If the poisoned bomb hits its target, the bomb deals damage as normal, but the target must also succeed at a saving throw against the poison or be affected by that poison. No other creatures are affected by the poison.</p>
</>};
const _profane_bomb = {title: "Profane Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-profane_bomb-profane-bomb">Profane Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-profane_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it deal evil divine damage. Good creatures that take a direct hit from a profane bomb must succeed at a Fortitude save or be <Link to="/misc/staggered">staggered</Link> on their next turn. Against a neutral creature, a profane bomb deals half damage, and the target is not affected by the bomb's staggering effect. A profane bomb has no effect against evil-aligned creatures.</p>
</>};
const _psychoactive_bomb = {title: "Psychoactive Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-psychoactive_bomb-psychoactive-bomb">Psychoactive Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-psychoactive_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Psychoactive bombs are mixed with neurotoxic extracts that heighten certain sensations. A creature struck by a psychoactive bomb takes a -1 penalty on saving throws against charm, emotion, fear, and pain effects, and the DC for Intimidate checks against the victim decreases by 2. This effect lasts for 1 hour per alchemist level. These penalties do not stack, and a creature can only be affected by a single psychoactive bomb at a time. A psychoactive bomb deals 1d6 fewer hit points of damage than normal.</p>
</>};
const _rocket_bomb = {title: "Rocket Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-rocket_bomb-rocket-bomb">Rocket Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-rocket_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>(<Link to="/race/goblin">Goblin</Link> only) Alchemists with this discovery can prepare special rockets to deliver their bombs. Rocket bombs travel farther and explode bigger than normal bombs, but cannot target individual creatures. Rocket bombs explode in a 20-foot radius, and all creatures in that area take the alchemist's normal splash damage. The range increment on a rocket bomb is 50 feet. Rocket bombs cannot be used with the <Link to="/discovery/precise_bombs">precise bombs</Link> or <Link to="/discovery/fast_bombs">fast bombs</Link> discoveries.</p>
</>};
const _sand_bomb = {title: "Sand Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-sand_bomb-sand-bomb">Sand Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook</Link><br/>When the alchemist creates a bomb, he can pack the casing full of sand that explodes in an abrasive cloud on impact. A creature that takes a direct hit from a sand bomb is <Link to="/misc/blinded">blinded</Link> for 1 round, as are any creatures in the splash radius that fail a Reflex save (DC = 10 + half the alchemist's level + his Intelligence modifier).</p>
</>};
const _scrap_bomb = {title: "Scrap Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-scrap_bomb-scrap-bomb">Scrap Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>(<Link to="/race/goblin">Goblin</Link> only) When the alchemist creates a bomb, he can choose to have it explode into shards of shrapnel that deal piercing damage. A creature that takes a direct hit from a scrap bomb takes 1 point of <Link to="/rule/bleed">bleed</Link> damage per die of bomb damage unless it succeeds at a Reflex save.</p>
</>};
const _shock_bomb = {title: "Shock Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-shock_bomb-shock-bomb">Shock Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>When the alchemist creates a bomb, he can choose to have it inflict electricity damage. Creatures that take a direct hit from a shock bomb are <Link to="/misc/dazzled">dazzled</Link> for 1d4 rounds.</p>
</>};
const _smoke_bomb = {title: "Smoke Bomb", addenda: ["primarybomb"], tree: ["Poison Bomb","Inferno Bomb","Plague Bomb","Greater Plague Bomb","Plague Vector","Stink Bomb"], jsx: <><h2 id="discovery-smoke_bomb-smoke-bomb">Smoke Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>When the alchemist creates a bomb, he can choose to have it create a cloud of thick smoke when it detonates. The cloud functions as <Link to="/spell/fog_cloud">fog cloud</Link>, filling an area equal to twice the bomb's splash radius for 1 round per level.</p>
</>};
const _inferno_bomb = {title: "Inferno Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-inferno_bomb-inferno-bomb">Inferno Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-inferno_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/smoke_bomb">smoke bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The effects of the smoke created by an alchemist's bomb duplicate the effects of <Link to="/spell/incendiary_cloud">incendiary cloud</Link> instead of <Link to="/spell/fog_cloud">fog cloud</Link>, filling an area equal to twice the bomb's splash radius for 1 round per level.</p>
</>};
const _plague_bomb = {title: "Plague Bomb", addenda: ["primarybomb"], tree: ["Greater Plague Bomb","Plague Vector"], jsx: <><h2 id="discovery-plague_bomb-plague-bomb">Plague Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-plague_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>8th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/smoke_bomb">smoke bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The effects of the smoke created by an alchemist's bomb duplicates the effects of <Link to="/spell/contagion">contagion</Link> instead of <Link to="/spell/fog_cloud">fog cloud</Link>, filling an area equal to twice the bomb's splash area for 1 round per level.</p>
</>};
const _greater_plague_bomb = {title: "Greater Plague Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-greater_plague_bomb-greater-plague-bomb">Greater Plague Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_plague_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discoveries:</strong> <Link to="/discovery/smoke_bomb">smoke bomb</Link>, <Link to="/discovery/plague_bomb">plague bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The effects of the smoke created by an alchemist's bomb duplicates the effects of <Link to="/spell/greater_contagion">greater contagion</Link> instead of <Link to="/spell/fog_cloud">fog cloud</Link>, filling an area equal to twice the bomb's splash radius for 1 round per level.</p>
</>};
const _plague_vector = {title: "Plague Vector", addenda: ["primarybomb"], jsx: <><h2 id="discovery-plague_vector-plague-vector">Plague Vector</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-plague_vector--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>14th level alchemist</li><li><strong>Discoveries:</strong> <Link to="/discovery/smoke_bomb">smoke bomb</Link>, <Link to="/discovery/plague_bomb">plague bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The effects of the alchemist's plague bomb operate as normal except for the following changes. The chosen disease's save DC is equal to 10 + 1/2 the alchemist's level + his Intelligence modifier. Any creatures affected by the chosen disease become vectors for it, spreading the disease to any creatures they come in physical contact with for a number of days equal to the alchemist's Intelligence modifier (minimum 1). The save DC to avoid contracting the disease from the vector is the same as the DC used for this discovery.</p>
</>};
const _poison_bomb = {title: "Poison Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-poison_bomb-poison-bomb">Poison Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-poison_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>12th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/smoke_bomb">smoke bomb</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The effects of the smoke created by an alchemist's bomb duplicates the effects of <Link to="/spell/cloudkill">cloudkill</Link> instead of <Link to="/spell/fog_cloud">fog cloud</Link>, filling an area equal to twice the bomb's splash radius for 1 round per level.</p>
</>};
const _stink_bomb = {title: "Stink Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-stink_bomb-stink-bomb">Stink Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-stink_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/smoke_bomb">smoke bomb</Link></td></tr></tbody></table></ScrollContainer></div><p>The effects of the smoke created by an alchemist's bomb can duplicate the effects of <Link to="/spell/stinking_cloud">stinking cloud</Link> instead of <Link to="/spell/fog_cloud">fog cloud</Link>, filling an area equal to twice the bomb's splash radius for 1 round. An alchemist must possess the <Link to="/discovery/smoke_bomb">smoke bomb</Link> discovery before selecting this discovery.</p>
</>};
const _solid_ground = {title: "Solid Ground", addenda: ["primarybomb"], jsx: <><h2 id="discovery-solid_ground-solid-ground">Solid Ground</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness</Link><br/>The alchemist launches an explosive paste bomb that bonds with any earthen surface. Each application of this paste deals no damage and affects a 5-foot-cube of dirt, loose soil, or stone, transmuting the earth for a number of minutes equal to the alchemist's level. Creatures cannot use burrow, <Link to="/kinetic/earthmeld">earthmeld</Link>, or similar abilities (such as the <Link to="/spell/meld_into_stone">meld into stone</Link> spell) while the ground remains transmuted in this way.</p>
</>};
const _substantiating_bomb = {title: "Substantiating Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-substantiating_bomb-substantiating-bomb">Substantiating Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-substantiating_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>10th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Your bombs are infused with ectoplasm and a longing for life, lending ethereal creatures a measure of substance. You can throw a bomb that inflicts no damage but instead creates a 10-foot-radius cloud of fog that functions as <Link to="/spell/fog_cloud">fog cloud</Link> and lasts for 1 round per alchemist level. Incorporeal creatures that pass through this cloud become partially solid, taking half damage from nonmagic attacks and full damage from magic weapons, spells, and spell-like abilities. This effect lasts for the duration of the smoke cloud, even if the incorporeal creature moves outside the cloud's area. A creature affected by the cloud can attempt a Will saving throw to negate the substantiating effects of this bomb.</p>
</>};
const _tanglefoot_bomb = {title: "Tanglefoot Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-tanglefoot_bomb-tanglefoot-bomb">Tanglefoot Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>A creature that takes a direct hit from a tanglefoot bomb must save against the bomb's DC or be <Link to="/rule/entangled">entangled</Link> and glued to the floor as if it had failed its save against a <Link to="/eq-weapon/tanglefoot_bag">tanglefoot bag</Link>. Creatures in the splash area that fail their saves are entangled but not glued to the floor; those who make this save are not entangled at all.</p>
</>};
const _thorny_bomb = {title: "Thorny Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-thorny_bomb-thorny-bomb">Thorny Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness</Link><br/>When the alchemist creates a bomb, he can choose to have it deal piercing damage. Thorny bombs count as magic weapons for the purpose of overcoming damage reduction.</p>
</>};
const _void_bomb = {title: "Void Bomb", addenda: ["primarybomb"], tree: ["Blackstar Bomb"], jsx: <><h2 id="discovery-void_bomb-void-bomb">Void Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-void_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>(<Link to="/race/drow">Drow</Link> only) By combining the spores from strange fungi with slivers from extradimensional voids, some drow alchemists create bombs that cause bursts of gravity capable of crushing those inside. Void bombs deals 1d4 points of bludgeoning damage, plus 1d4 points of bludgeoning damage for every 2 alchemist levels beyond 1st, instead of 1d6. A creature hit by the bomb must succeed at a Reflex save against the bomb's DC. If it fails, it is knocked <Link to="/rule/prone">prone</Link> and can't get up for 1 round. If it succeeds, all of its movement speeds are reduced to 5 feet for 1 round. Other creatures within 5 feet of the bomb's target take no damage, but must succeed at a Reflex save against the bomb's DC or have all their movement speeds reduced to 5 feet for 1 round.</p>
</>};
const _blackstar_bomb = {title: "Blackstar Bomb", addenda: ["primarybomb"], jsx: <><h2 id="discovery-blackstar_bomb-blackstar-bomb-su">Blackstar Bomb (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-blackstar_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/void_bomb">void bomb</Link></td></tr></tbody></table></ScrollContainer></div><p>This bomb crushes the target like a void bomb, then repels nearby creatures with a burst of gravity. The target takes damage as if hit by a void bomb. All other creatures within 5 feet of the target are subject to a <Link to="/rule/bull_rush">bull rush</Link>. The alchemist uses his alchemist class level in place of his Combat Maneuver Bonus, and adds his Intelligence modifier in place of his Strength or Dexterity modifier to resolve the bull rush attempts. Creatures moved by a blackstar bomb are pushed directly away from the target's square.</p>
</>};
const _delayed_bomb = {title: "Delayed Bomb", tree: ["Tainted Infusion"], jsx: <><h2 id="discovery-delayed_bomb-delayed-bomb">Delayed Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-delayed_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist can place a bomb so that it explodes a number of rounds after the alchemist ceases contact with the bomb. This delay can be any number of rounds as chosen by the alchemist, up to a number of rounds equal to his level. If at any point the alchemist reclaims possession of the delayed bomb, he can end the timer and prevent the bomb's detonation. A delayed bomb detonates immediately if any other creature attempts to touch or move it, or if the bomb's contents are removed from the vial (such as if the vial breaks). The bomb deals damage as if it scored a direct hit to any creature in the square with the bomb when it detonates, and splash damage to all adjacent creatures as normal. An alchemist cannot have more than one delayed bomb at one time. If he creates another delayed bomb, the previous bomb becomes inert. <Link to="/spell/dispel_magic">Dispel magic</Link> can neutralize a delayed bomb, as can a successful Disable Device check (DC equals 10 + the alchemist's level + the alchemist's Intelligence modifier).</p>
</>};
const _directed_bomb = {title: "Directed Bomb", jsx: <><h2 id="discovery-directed_bomb-directed-bomb">Directed Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace</Link><br/>The alchemist can cause his bombs to splash in a 15-foot cone instead of a 5-foot-radius <Link to="/misc/burst">burst</Link>. The alchemist chooses the direction of the cone. If the attack misses, roll an additional 1d8 to determine the direction of the blast from where the bomb lands. This discovery can't be combined with the <Link to="/discovery/explosive_bomb">explosive bomb</Link> discovery.</p>
</>};
const _divine_inks = {title: "Divine Inks", tree: ["Improved Divine Inks","Greater Divine Inks","Constructive Dyes","Greater Constructive Dyes","Living Pigment"], jsx: <><h2 id="discovery-divine_inks-divine-inks">Divine Inks</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion</Link><br/>The alchemist can develop special pigments and combine them with his alchemical reagents to create unique dyes that cling to the empty space around him, allowing him to paint images in the air to fool his enemies. By expending two daily uses of his bombs, he can use the dyes to create an image in a space adjacent to him, as <Link to="/spell/silent_image">silent image</Link>, using his alchemist level as the spell's caster level. The image he creates remains for a number of minutes equal to his alchemist level. He can dismiss this image as a standard action.</p>
</>};
const _improved_divine_inks = {title: "Improved Divine Inks", tree: ["Greater Divine Inks"], jsx: <><h2 id="discovery-improved_divine_inks-improved-divine-inks">Improved Divine Inks</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-improved_divine_inks--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>4th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/divine_inks">divine inks</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's unique dyes allow him to create images accompanied by sound. If he expends an additional daily use of his bombs, the image he creates with the divine inks discovery also produces minor sounds, as <Link to="/spell/minor_image">minor image</Link>.</p>
</>};
const _greater_divine_inks = {title: "Greater Divine Inks", jsx: <><h2 id="discovery-greater_divine_inks-greater-divine-inks">Greater Divine Inks</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_divine_inks--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>6th level alchemist</li><li><strong>Discoveries:</strong> <Link to="/discovery/divine_inks">divine inks</Link>, <Link to="/discovery/improved_divine_inks">improved divine inks</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's unique dyes allow him to create lifelike images. If he expends an additional daily use of his bombs, the image he creates with the divine inks discovery also produces sound, smell, and heat, as <Link to="/spell/major_image">major image</Link>.</p>
</>};
const _constructive_dyes = {title: "Constructive Dyes", tree: ["Greater Constructive Dyes"], jsx: <><h2 id="discovery-constructive_dyes-constructive-dyes">Constructive Dyes</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-constructive_dyes--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>8th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/divine_inks">divine inks</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's dyes congeal and solidify, allowing him to make physical objects from them. The alchemist can expend two uses of his daily bombs to create a nonmagical object, as <Link to="/spell/minor_creation">minor creation</Link>, using his alchemist level as the spell's caster level.</p>
</>};
const _greater_constructive_dyes = {title: "Greater Constructive Dyes", jsx: <><h2 id="discovery-greater_constructive_dyes-greater-constructive-dyes">Greater Constructive Dyes</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_constructive_dyes--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>10th level alchemist</li><li><strong>Discoveries:</strong> <Link to="/discovery/divine_inks">divine inks</Link>, <Link to="/discovery/constructive_dyes">constructive dyes</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist expands the set of objects he can create with his constructive dyes. The alchemist can expend one additional use of his daily bombs when using his constructive dyes discovery to create objects, as <Link to="/spell/major_creation">major creation</Link>.</p>
</>};
const _living_pigment = {title: "Living Pigment", jsx: <><h2 id="discovery-living_pigment-living-pigment">Living Pigment</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-living_pigment--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/divine_inks">divine inks</Link></td></tr></tbody></table></ScrollContainer></div><p>The alchemist infuses his inks and dyes with a spark of animating force. As a standard action, he can expend one daily use of his bombs and a 1st-level extract he has prepared to create a creature, as <Link to="/spell/summon_monster_i">summon monster I</Link>, using his level as the spell's caster level. The extract is expended as if the alchemist had consumed it. The alchemist can expend a higher-level extract when using this ability to create a creature using a <Link to="/spell/summon_monster">summon monster</Link> spell of a level equal to the level of extract expended. For example, if the alchemist expends a 4th-level extract, he can create a creature as if using <Link to="/spell/summon_monster_iv">summon monster IV</Link>. Additionally, the alchemist can expend an additional use of his daily bombs when creating a creature in this way to grant the creature the <Link to="/template/celestial">celestial</Link> or <Link to="/template/fiendish">fiendish</Link> template.</p>
</>};
const _dispelling_bomb = {title: "Dispelling Bomb", jsx: <><h2 id="discovery-dispelling_bomb-dispelling-bomb">Dispelling Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-dispelling_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates a bomb, he can choose to have it dispel magic effects instead of deal damage. Creatures that take a direct hit from a dispelling bomb are subject to a targeted <Link to="/spell/dispel_magic">dispel magic</Link> spell, using the alchemist's level as the caster level. This cannot be used to target a specific spell effect.</p>
</>};
const _explosive_calligraphy = {title: "Explosive Calligraphy", jsx: <><h2 id="discovery-explosive_calligraphy-explosive-calligraphy">Explosive Calligraphy</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-explosive_calligraphy--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist can create especially volatile pigments that detonate when agitated. This requires expending one daily use of his bombs, but otherwise functions as <Link to="/spell/explosive_runes">explosive runes</Link> except that it deals damage as one of the alchemist's bombs. The alchemist can expend an additional daily use of his bombs to apply one discovery that applies to his bombs, such as <Link to="/discovery/acid_bomb">acid bomb</Link> or <Link to="/discovery/dispelling_bomb">dispelling bomb</Link>, to the runes created with this discovery.</p>
</>};
const _explosive_missile = {title: "Explosive Missile", jsx: <><h2 id="discovery-explosive_missile-explosive-missile">Explosive Missile</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-explosive_missile--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>As a standard action, the alchemist can infuse a single arrow, crossbow bolt, or one-handed firearm bullet with the power of his bomb, load the ammunition, and shoot the ranged weapon. He must be proficient with the weapon in order to accomplish this. When the infused ammunition hits its target, it deals damage normally and detonates as if the alchemist had thrown the bomb at the target. If the explosive missile misses, it does not detonate.</p>
</>};
const _fast_bombs = {title: "Fast Bombs", jsx: <><h2 id="discovery-fast_bombs-fast-bombs">Fast Bombs</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-fast_bombs--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>An alchemist with this discovery can quickly create enough bombs to throw more than one in a single round. The alchemist can prepare and throw additional bombs as a full-round action if his base attack bonus is high enough to grant him additional attacks. This functions just like a full-attack with a ranged weapon.</p>
</>};
const _fire_brand = {title: "Fire Brand", jsx: <><h2 id="discovery-fire_brand-fire-brand">Fire Brand</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>(<Link to="/race/goblin">Goblin</Link> only) An alchemist with this discovery can expend one daily bomb use to apply the bomb reagents to his weapon as a swift action. A weapon treated this way deals fire damage as if it had the <Link to="/magic-enh/flaming">flaming</Link> weapon special ability. At 10th level, the weapon is treated as if it had the <Link to="/magic-enh/flaming_burst">flaming burst</Link> weapon special ability. The bomb reagents continue burning for 1 minute or until extinguished by dousing the weapon in water. An alchemist can use this ability with natural weapons, but he takes 1d6 points of fire damage per round for each natural weapon treated.</p>
</>};
const _madness_bomb = {title: "Madness Bomb", jsx: <><h2 id="discovery-madness_bomb-madness-bomb">Madness Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-madness_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>12th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist's bombs do more than sear flesh - they sear the mind. A creature that takes a direct hit from a madness bomb takes damage from the bomb plus 1d4 points of <Link to="/rule/wisdom_damage">Wisdom damage</Link>. Reduce the amount of normal damage dealt by the bomb by 2d6 (so a bomb that would normally deal 6d6+4 points of damage deals 4d6+4 points of damage instead). The amount of Wisdom damage dealt by a madness bomb is reduced by 1 for each madness bomb that hit the target in the past 24 hours, to a minimum of 1 point of Wisdom damage.</p>
</>};
const _inspired_bomb = {title: "Inspired Bomb", jsx: <><h2 id="discovery-inspired_bomb-inspired-bomb">Inspired Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide</Link><br/>An alchemist with this discovery and a pool of inspiration (by way of a class feature, a feat, or the <Link to="/discovery/inspiring_cognatogen">inspiring cognatogen</Link> discovery) can expend two uses of inspiration to increase the bomb's damage by 1d6. The type of damage the bomb deals does not change. Unlike other a discoveries that affect bombs, this one can be applied to a bomb with another bomb discovery, though it cannot be applied to the same bomb more than once.</p>
</>};
const _precise_bombs = {title: "Precise Bombs", jsx: <><h2 id="discovery-precise_bombs-precise-bombs">Precise Bombs</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>Whenever the alchemist throws a bomb, he can select a number of squares equal to his Intelligence modifier that are not affected by the splash damage from his bombs. If the bomb misses, this discovery has no effect.</p>
</>};
const _sticky_bomb = {title: "Sticky Bomb", jsx: <><h2 id="discovery-sticky_bomb-sticky-bomb">Sticky Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-sticky_bomb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>10th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The effects of the alchemist's bombs are persistent and continue to damage creatures for 1 round after the initial damage. Creatures that take a direct hit from a sticky bomb take the splash damage 1 round later. Bombs that have effects that would normally occur 1 round later instead have those effects occur 2 rounds later.</p>
</>};
const _strafe_bomb = {title: "Strafe Bomb", jsx: <><h2 id="discovery-strafe_bomb-strafe-bomb">Strafe Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>The alchemist can throw bombs that splash in a 40-foot line rather than affecting a radius. The line starts at the alchemist and extends away from him in the direction he chooses. The alchemist designates one creature in the squares affected by the line to be the target of the bomb and makes his attack roll against that creature; all other squares in the line take splash damage. If the alchemist has the <Link to="/discovery/explosive_bomb">explosive bomb</Link> discovery and throws an explosive strafe bomb, the line of splash damage is 80 feet long instead of 40 feet.</p>
</>};
const _syringe_stirge = {title: "Syringe Stirge", jsx: <><h2 id="discovery-syringe_stirge-syringe-stirge">Syringe Stirge</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-syringe_stirge--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>As a full-round action, you can expend two daily uses of bombs to create a syringe stirge, a tiny construct primed with a bomb (if you have multiple types of bombs, you must select which type the syringe stirge carries when created). Undirected, they take no actions except to flock around you in your square and follow you as best they can. They can be attacked normally, but gain <Link to="/rule/cover">cover</Link> while occupying your square. As a swift action, you can order one of your syringe stirges to attack an enemy it can see. Once ordered to attack that enemy, the syringe stirge will continue to attack every round, attempting to attach and deliver its payload.</p>
<p>A syringe stirge has all of the statistics of a <Link to="/monster/stirge">stirge</Link> but lacks the blood drain ability. If it ends its turn attached to an opponent, it injects your bomb into the opponent's bloodstream, dealing damage as a direct hit plus the alchemist's Intelligence modifier (as the <Link to="/feat/throw_anything">Throw Anything</Link> feat - this injection is a direct attack and doesn't deal splash damage). A syringe stirge dies immediately after injecting its bomb. A syringe stirge lasts for 1 minute per alchemist level or until destroyed; if it has not attached to an enemy before the end of its life span it and its bomb payload fall inert.</p>
</>};
const _underwater_demolition = {title: "Underwater Demolition", jsx: <><h2 id="discovery-underwater_demolition-underwater-demolition">Underwater Demolition</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>The alchemist gains the ability to throw bombs underwater (normally, thrown weapons cannot be used underwater), including throwing from the air into the water. If the bomb travels through water, the range increment is reduced to 5 feet.</p>
</>};
const _bottled_ooze = {title: "Bottled Ooze", jsx: <><h2 id="discovery-bottled_ooze-bottled-ooze">Bottled Ooze</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-bottled_ooze--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist has learned how to preserve a sample of oozes in a sealed bottle, which he can prepare for use as an extract. When the alchemist activates the extract, he actually throws the bottle at a square within 30 feet, releasing the ooze, which reconstitutes and attacks the closest creature. The ooze is not under the alchemist's control, but is otherwise treated as a summoned creature. The ooze remains for 1 round per caster level, and decays into powder when the duration expires. If the alchemist has the <Link to="/discovery/infusion">infusion</Link> discovery, another character can use the infused specimen. Creating a bottled ooze requires an extract with a level equal to the ooze's CR (so a CR 4 <Link to="/monster/gray_ooze">gray ooze</Link> requires a 4th-level extract).</p>
</>};
const _combine_extracts = {title: "Combine Extracts", jsx: <><h2 id="discovery-combine_extracts-combine-extracts">Combine Extracts</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-combine_extracts--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates an extract, he can place two formulae into one extract. When the extract is consumed, both formulae take effect. This extract has a level two levels higher than the highest-level formulae placed in the extract.</p>
</>};
const _infusion = {title: "Infusion", tree: ["Aromatic Extract","Change Alignment","Glimmering Infusion","Nostrum","Tainted Infusion","Greater Change Alignment"], jsx: <><h2 id="discovery-infusion-infusion">Infusion</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>When the alchemist creates an extract, he can infuse it with an extra bit of his own magical power. The extract created now persists even after the alchemist sets it down. As long as the extract exists, it continues to occupy one of the alchemist's daily extract slots. An infused extract can be imbibed by a non-alchemist to gain its effects.</p>
</>};
const _aromatic_extract = {title: "Aromatic Extract", jsx: <><h2 id="discovery-aromatic_extract-aromatic-extract">Aromatic Extract</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-aromatic_extract--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>10th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/infusion">infusion</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist creates an inhaled version of an extract that is shared among multiple creatures. He must decide that an extract is an aromatic extract when he makes it. When used, the extract grants its benefit to all creatures within a 10-foot <Link to="/misc/spread">spread</Link> of the extract. The aromatic extract is treated as having the minimum caster level required for the original extract. An aromatic extract expends one of the alchemist's daily extracts as if it were an extract 2 levels higher. This discovery can be applied only to extracts with a range of touch.</p>
</>};
const _change_alignment = {title: "Change Alignment", tree: ["Greater Change Alignment"], jsx: <><h2 id="discovery-change_alignment-change-alignment">Change Alignment</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-change_alignment--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>12th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/infusion">infusion</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>Once per day as part of his preparation of infusions, the alchemist can brew an infusion that shifts the imbiber's alignment to good. This change in alignment lasts for 10 minutes per alchemist level. An unwilling creature receives a Will save to resist this change. The alchemist may have only one such infusion at any one time. The effects of this infusion may have serious repercussions for a creature suddenly struggling with a new outlook. Many see it as little more than forced insanity, and some good faiths outlaw its use.</p>
</>};
const _glimmering_infusion = {title: "Glimmering Infusion", jsx: <><h2 id="discovery-glimmering_infusion-glimmering-infusion">Glimmering Infusion</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-glimmering_infusion--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/infusion">infusion</Link></td></tr></tbody></table></ScrollContainer></div><p>The alchemist can expend any prepared extract to produce a cube of glowing motes that act as per <Link to="/spell/glitterdust">glitterdust</Link>. The area must be adjacent to the alchemist and covers one 5-foot square per level of extract sacrificed, and the effect's save DC is calculated using the level of the sacrificed extract.</p>
</>};
const _nostrum = {title: "Nostrum", jsx: <><h2 id="discovery-nostrum-nostrum">Nostrum</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-nostrum--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/infusion">infusion</Link></td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates an infusion, he can mask a delayed poison within the mixture. A nostrum can contain only an ingested poison, and the save DC of the poison is reduced by 2. The poison takes effect a number of hours after being imbibed equal to the alchemist's Intelligence bonus (minimum 0) decided by the alchemist at the creation of the nostrum. The poison within a nostrum can be detected as normal by spells such as <Link to="/spell/detect_poison">detect poison</Link> and similar abilities. Until the nostrum is consumed or destroyed, it continues to occupy one of the alchemist's daily extract slots.</p>
</>};
const _tainted_infusion = {title: "Tainted Infusion", jsx: <><h2 id="discovery-tainted_infusion-tainted-infusion">Tainted Infusion</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-tainted_infusion--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discoveries:</strong> <Link to="/discovery/delayed_bomb">delayed bomb</Link>, <Link to="/discovery/infusion">infusion</Link></td></tr></tbody></table></ScrollContainer></div><p>The alchemist can mask murder behind beneficence. When preparing an extract with the infusion discovery, he can lace the extract with one of his bombs as long as the extract has a duration greater than instantaneous. If he chooses, the alchemist can reduce the duration of the extract to 1 round. As soon as the extract's duration expires, it detonates, dealing 150% of the alchemist's bomb damage to the drinker. This effect does not produce a splash radius. Producing a tainted extract consumes both an infusion slot and a daily bomb use.</p>
</>};
const _intuitive_understanding = {title: "Intuitive Understanding", jsx: <><h2 id="discovery-intuitive_understanding-intuitive-understanding">Intuitive Understanding</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-intuitive_understanding--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>4th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/cognatogen">cognatogen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>If the alchemist drinks an extract of the divination school while under the effects of a cognatogen, his effective caster level temporarily increases by 2. In addition, while under the effects of a cognatogen, the alchemist may use <Link to="/spell/augury">augury</Link> once as a spell-like ability (caster level equal to his alchemist level). At 10th level, he can use <Link to="/spell/divination">divination</Link> instead.</p>
</>};
const _lingering_plague = {title: "Lingering Plague", jsx: <><h2 id="discovery-lingering_plague-lingering-plague">Lingering Plague</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-lingering_plague--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Any creature that must make a save against a disease caused by the alchemist's extract or other class ability must make a second save 1 round later to avoid doubling the duration of the disease effect. If the disease doesn't have a duration, this discovery reduces its onset time and frequencies by half.</p>
</>};
const _pickled_quasit = {title: "Pickled Quasit", jsx: <><h2 id="discovery-pickled_quasit-pickled-quasit">Pickled Quasit</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-pickled_quasit--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>10th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist has learned how to seal a <Link to="/monster/quasit">quasit</Link> in a bottle, which he can prepare for use as an extract. When the alchemist activates the extract, he throws the bottle at a square within 30 feet, releasing the quasit. The quasit is not under the alchemist's control, but is otherwise treated as a summoned creature. The quasit remains for 1 round per caster level, then collapses into its associated elements. If the alchemist has the <Link to="/discovery/infusion">infusion</Link> discovery, another character can use the infused specimen. Creating a pickled quasit requires a 4th-level extract.</p>
</>};
const _remedy_extract = {title: "Remedy Extract", jsx: <><h2 id="discovery-remedy_extract-remedy-extract">Remedy Extract</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-remedy_extract--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist creates an extract, he can add one nonmagical <Link to="/main/equipment_alchemical">alchemical remedy</Link> (such as an <Link to="/eq-misc/antitoxin">antitoxin</Link>) to it. When the extract is consumed, both the formula and the alchemical remedy take effect. The extract has a level 1 higher than normal. This discovery cannot be combined with other methods of combining multiple consumed items or extracts into one.</p>
</>};
const _sandstone_solution = {title: "Sandstone Solution", jsx: <><h2 id="discovery-sandstone_solution-sandstone-solution">Sandstone Solution</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link><br/>As a full-round action, the alchemist can convert any potion or extract into a solution that, when thrown or applied, solidifies sand or dirt to the hardness of stone for 1 hour, affecting an area with a radius of 10 feet &times; the level of the potion or extract. If this solution is thrown at or applied to stone, it instead causes a 5-foot cube of stone to become crumbly and soft for 1 minute, reducing its hardness by double the level of the potion or extract.</p>
</>};
const _volumizer = {title: "Volumizer", jsx: <><h2 id="discovery-volumizer-volumizer">Volumizer</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness</Link><br/>The alchemist can use an extract slot of any level to create a reactive tablet that purifies water and doubles its volume. This works like <Link to="/spell/purify_food_and_drink">purify food and drink</Link> for a maximum volume of water equal to 1 gallon for each level the alchemist has &times; the level of the extract slot the alchemist used to create the tablet. Additionally, if the alchemist has a receptacle of sufficient volume to gather the water, the tablet doubles the volume of pure water. The water volume increases over the course of 1 minute, but the effect stops before it can create significant water pressure on a container that's not large enough to hold the entire volume. An unused tablet remains usable until the next time the alchemist recovers extract slots.</p>
</>};
const _bone_spike_mutagen = {title: "Bone-Spike Mutagen", jsx: <><h2 id="discovery-bone_spike_mutagen-bone-spike-mutagen">Bone-Spike Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-bone_spike_mutagen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist imbibes a mutagen, he mutates his skeletal structure, causing the bones on his elbows, knuckles, spine, and shoulder blades to grow massive and pierce his skin, exposing themselves as large spikes. While the mutagen is in effect, the alchemist's natural armor bonus granted by the mutagen increases by 2. The spikes count as masterwork <Link to="/eq-armorenh/armor_spikes">armor spikes</Link> with which the alchemist is proficient.</p>
</>};
const _cognatogen = {title: "Cognatogen", tree: ["Intuitive Understanding","Collective Memory","Greater Cognatogen","Grand Cognatogen"], jsx: <><h2 id="discovery-cognatogen-cognatogen">Cognatogen</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>The alchemist gains the ability to create a cognatogen, a mutagen-like mixture that heightens one mental ability score at the expense of a physical ability score. If the cognatogen enhances his Intelligence, it applies a penalty to his Strength. If it enhances his Wisdom, it applies a penalty to his Dexterity. If it enhances his Charisma, it applies a penalty to his Constitution. Otherwise, this ability works just like the mutagen ability (including the natural armor bonus). Anytime the alchemist would prepare a mutagen, he may instead prepare a cognatogen. All limitations of mutagens apply to cognatogens as if they were the same substance - an alchemist can only maintain one mutagen or cognatogen at a time, a cognatogen that is not in an alchemist's possession becomes inert, drinking a cognatogen makes a non-alchemist sick, and so on. When the effect of the cognatogen ends, the alchemist takes 2 points of ability damage to the ability score penalized by the cognatogen. The <Link to="/discovery/infuse_mutagen">infuse mutagen</Link> discovery and the persistent mutagen class ability apply to cognatogens.</p>
</>};
const _collective_memory = {title: "Collective Memory", jsx: <><h2 id="discovery-collective_memory-collective-memory">Collective Memory</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-collective_memory--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/cognatogen">cognatogen</Link></td></tr></tbody></table></ScrollContainer></div><p>While under the effects of a cognatogen, the alchemist adds half his class level on all Knowledge skill checks and may attempt all Knowledge skill checks untrained. This bonus does not stack with the second Intelligence bonus granted by the mindchemist archetype's perfect recall class feature.</p>
</>};
const _greater_cognatogen = {title: "Greater Cognatogen", tree: ["Grand Cognatogen"], jsx: <><h2 id="discovery-greater_cognatogen-greater-cognatogen">Greater Cognatogen</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_cognatogen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>12th level alchemist</li><li><strong>Discovery or Class Feature:</strong> <Link to="/discovery/cognatogen">cognatogen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's mutagen now grants a +4 natural armor bonus, a +6 alchemical bonus to one mental ability score (Intelligence, Wisdom, or Charisma), and a +4 alchemical bonus to a second mental ability score. The alchemist takes a -2 penalty on both associated physical ability scores as long as the mutagen persists, and takes 2 points of ability damage to both associated physical ability scores when the cognatogen ends.</p>
</>};
const _grand_cognatogen = {title: "Grand Cognatogen", jsx: <><h2 id="discovery-grand_cognatogen-grand-cognatogen">Grand Cognatogen</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-grand_cognatogen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discoveries or Class Abilities:</strong> <Link to="/discovery/cognatogen">cognatogen</Link>, <Link to="/discovery/greater_cognatogen">greater cognatogen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's cognatogen now grants a +6 natural armor bonus, a +8 alchemical bonus to one mental ability score (Intelligence, Wisdom, or Charisma), a +6 alchemical bonus to a second mental ability score, and a +4 alchemical bonus to a third mental ability score. The alchemist takes a -2 penalty to his Strength, Dexterity, and Constitution as long as the cognatogen persists, and takes 2 points of ability damage to each physical ability score when the cognatogen ends.</p>
</>};
const _elemental_mutagen = {title: "Elemental Mutagen", jsx: <><h2 id="discovery-elemental_mutagen-elemental-mutagen">Elemental Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace</Link><br/>The alchemist chooses an element (air, earth, fire, or water). Whenever the alchemist imbibes a mutagen, he gains resistance 5 to the associated energy type and a +2 competence bonus on an associated skill check. This resistance increases by 5 and the competence bonus by 2 for each of the following discoveries the alchemist possesses: grand mutagen, greater mutagen, and true mutagen. The elements and their associated energies and skills are air (electricity, Fly), earth (acid, Climb), fire (fire, Acrobatics), and water (cold, Swim). An alchemist can select this discovery up to four times, but must choose a different element each time. An alchemist can gain the benefits of only one elemental mutagen at a time, selected when he imbibes the mutagen.</p>
</>};
const _feral_mutagen = {title: "Feral Mutagen", jsx: <><h2 id="discovery-feral_mutagen-feral-mutagen">Feral Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>Whenever the alchemist imbibes a mutagen, he gains two claw attacks and a bite attack. These are <Link to="/rule/natural_attacks">primary attacks</Link> and are made using the alchemist's full base attack bonus. The claw attacks deal 1d6 points of damage (1d4 if the alchemist is Small) and the bite attack deals 1d8 points of damage (1d6 if the alchemist is Small). While the mutagen is in effect, the alchemist gains a +2 competence bonus on Intimidate skill checks.</p>
</>};
const _fey_mutagen = {title: "Fey Mutagen", tree: ["Greater Fey Mutagen","Grand Fey Mutagen"], jsx: <><h2 id="discovery-fey_mutagen-fey-mutagen">Fey Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link><br/>The alchemist gains the ability to create a fey mutagen, a mixture that lends him some of the grace and power of the First World. When imbibed, a fey mutagen grants a +2 alchemical bonus to the alchemist's Dexterity and Charisma, a -2 penalty to his Strength, and DR 2/cold iron. This otherwise works like the standard mutagen class feature and interacts with other effects as though it were a mutagen.</p>
</>};
const _greater_fey_mutagen = {title: "Greater Fey Mutagen", tree: ["Grand Fey Mutagen"], jsx: <><h2 id="discovery-greater_fey_mutagen-greater-fey-mutagen">Greater Fey Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_fey_mutagen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>12th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/fey_mutagen">fey mutagen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's fey mutagen now grants a +4 alchemical bonus to Dexterity and Charisma, a -2 penalty to his Strength, DR 5/cold iron, and the druid's <Link to="/ability/woodland_stride">woodland stride</Link> class feature.</p>
</>};
const _grand_fey_mutagen = {title: "Grand Fey Mutagen", jsx: <><h2 id="discovery-grand_fey_mutagen-grand-fey-mutagen">Grand Fey Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-grand_fey_mutagen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discoveries:</strong> <Link to="/discovery/fey_mutagen">fey mutagen</Link>, <Link to="/discovery/greater_fey_mutagen">greater fey mutagen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's fey mutagen now grants a +6 alchemical bonus to Dexterity and Charisma, a -2 penalty to his Strength, DR 10/cold iron, and the druid's <Link to="/ability/woodland_stride">woodland stride</Link> class feature. In addition, he can choose not to allow spells and effects to affect him if they would not be capable of affecting both his original creature type and the fey creature type.</p>
</>};
const _greater_mutagen = {title: "Greater Mutagen", tree: ["Grand Mutagen"], jsx: <><h2 id="discovery-greater_mutagen-greater-mutagen">Greater Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_mutagen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>12th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist's mutagen now grants a +4 natural armor bonus, a +6 alchemical bonus to one physical ability score (Strength, Dexterity, or Constitution), and a +4 alchemical bonus to a second physical ability score. The alchemist takes a -2 penalty on both associated mental ability scores as long as the mutagen persists.</p>
</>};
const _grand_mutagen = {title: "Grand Mutagen", tree: ["True Mutagen"], jsx: <><h2 id="discovery-grand_mutagen-grand-mutagen">Grand Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-grand_mutagen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/greater_mutagen">greater mutagen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's mutagen now grants a +6 natural armor bonus, a +8 alchemical bonus to one ability score (Strength, Dexterity, or Constitution), a +6 alchemical bonus to a second physical ability score, and a +4 alchemical bonus to a third physical ability score. The alchemist takes a -2 penalty to his Intelligence, Wisdom, and Charisma as long as the mutagen persists.</p>
</>};
const _greater_rasugen = {title: "Greater Rasugen", tree: ["Grand Rasugen"], jsx: <><h2 id="discovery-greater_rasugen-greater-rasugen">Greater Rasugen</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_rasugen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>12th level alchemist</li><li>Must be able to <Link to="/arc-alchemist/mnemostiller">brew a rasugen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's rasugen now grants a +4 alchemical bonus on all saving throws, 3 <Link to="/rule/temporary_hit_points">temporary hit points</Link> per alchemist level, and immunity to mind-affecting effects. The alchemist takes a -4 penalty to Intelligence as long as the greater rasugen persists.</p>
</>};
const _grand_rasugen = {title: "Grand Rasugen", jsx: <><h2 id="discovery-grand_rasugen-grand-rasugen">Grand Rasugen</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-grand_rasugen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/greater_rasugen">greater rasugen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's rasugen now grants a +6 alchemical bonus on all saving throws, 4 <Link to="/rule/temporary_hit_points">temporary hit points</Link> per alchemist level, and immunity to disease, mind-affecting effects, and poison. The alchemist takes a -6 penalty to Intelligence and a -2 penalty to Charisma and Wisdom as long as the grand rasugen persists.</p>
</>};
const _infuse_mutagen = {title: "Infuse Mutagen", jsx: <><h2 id="discovery-infuse_mutagen-infuse-mutagen">Infuse Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>When the alchemist creates a mutagen, he can infuse it with an extra bit of his own magical power. This inflicts 2 points of <Link to="/rule/intelligence_damage">Intelligence damage</Link> to the alchemist and costs 1,000 gp in rare reagents, but the mutagen created persists on its own and is not rendered inert if the alchemist creates another mutagen. This allows an alchemist to create different types of mutagens and keep them handy for emergencies. This does not allow an alchemist to gain the effects of multiple mutagens - only the most recently imbibed mutagen has any effect.</p>
</>};
const _inspiring_cognatogen = {title: "Inspiring Cognatogen", tree: ["Greater Inspiring Cognatogen","Grand Inspiring Cognatogen"], jsx: <><h2 id="discovery-inspiring_cognatogen-inspiring-cognatogen">Inspiring Cognatogen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide</Link><br/>An alchemist with this discovery leans how to make an inspiring cognatogen, a mutagen-like mixture that grants him inspiration (as the <Link to="/class/investigator">investigator's</Link> class feature) at the expense of Strength and Constitution. Upon drinking the inspiring cognatogen, the alchemist gains a pool of inspiration equal to 1/2 his alchemist level + his Intelligence modifier (minimum 1). He also gains a +2 dodge bonus to AC and takes a -2 penalty to both Strength and Constitution.</p>
<p>As a free action, the alchemist can add 1d6 to the result of an ability or skill check (including any he takes 10 or 20 on) by expending one use of inspiration. This ability works exactly like the investigator's inspiration ability, except that the alchemist gains the pool of inspiration upon drinking the inspiring cognatogen, and any unspent inspiration is lost at the end of the cognatogen's duration. If the alchemist already has access to inspiration, the inspiration added by the inspiring cognatogen is added to his inspiration pool, but each time he expends at least one use of inspiration while this ability is active, he must succeed at a DC 20 Will saving throw or become <Link to="/misc/dazed">dazed</Link> for 1 round. He cannot use inspiration to augment this saving throw.</p>
<p>All limitations of mutagens apply to an inspiring cognatogen as if they were the same substance - an alchemist can only maintain one mutagen or cognatogen (either the standard <Link to="/discovery/cognatogen">cognatogen</Link> or the inspired cognatogen) at a time, a cognatogen not in an alchemist's possession becomes inert, drinking a cognatogen makes non-alchemists sick, and so on. When the effect of an inspiring cognatogen ends, the alchemist takes 2 points of ability damage to Strength and Dexterity. The <Link to="/discovery/infuse_mutagen">infuse mutagen</Link> discovery and the persistent mutagen class ability apply to an inspiring cognatogen.</p>
</>};
const _greater_inspiring_cognatogen = {title: "Greater Inspiring Cognatogen", tree: ["Grand Inspiring Cognatogen"], jsx: <><h2 id="discovery-greater_inspiring_cognatogen-greater-inspiring-cognatogen">Greater Inspiring Cognatogen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_inspiring_cognatogen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>12th level alchemist</li><li><strong>Discovery or Class Feature:</strong> <Link to="/discovery/inspiring_cognatogen">inspiring cognatogen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's inspiring cognatogen now grants a +2 dodge bonus to AC and a +2 bonus to Reflex saving throws; a -4 penalty to Strength and Constitution; and the effects of having the <Link to="/invtalent/amazing_inspiration">amazing inspiration</Link>, <Link to="/invtalent/eidetic_recollection">eidetic recollection</Link>, and <Link to="/invtalent/expanded_inspiration">expanded inspiration</Link> investigator talents.</p>
</>};
const _grand_inspiring_cognatogen = {title: "Grand Inspiring Cognatogen", jsx: <><h2 id="discovery-grand_inspiring_cognatogen-grand-inspiring-cognatogen">Grand Inspiring Cognatogen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-grand_inspiring_cognatogen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/greater_inspiring_cognatogen">greater inspiring cognatogen</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's inspiring cognatogen now grants a +4 dodge bonus to AC and a +4 bonus to Reflex saving throws; a -6 penalty to Strength and Constitution; and the effects of having the <Link to="/invtalent/item_lore">item lore</Link>, <Link to="/invtalent/tenacious_inspiration">tenacious inspiration</Link>, and <Link to="/invtalent/underworld_inspiration">underworld inspiration</Link> investigator talents.</p>
</>};
const _mutagen = {title: "Mutagen", jsx: <><h2 id="discovery-mutagen-mutagen">Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>This discovery gives the alchemist the mutagen class ability. (This discovery exists so alchemist archetypes who have variant mutagens, such as the <Link to="/arc-alchemist/mindchemist">mindchemist</Link>, can learn how to make standard mutagens.)</p>
</>};
const _purging_mutagen = {title: "Purging Mutagen", jsx: <><h2 id="discovery-purging_mutagen-purging-mutagen">Purging Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>The alchemist's mutagen combines ipecac and other purgative components. A non-alchemist who consumes the mutagen is nauseated for only 1 round, during which time her body rapidly metabolizes or expels all extant toxins, granting her an immediate second saving throw against each ongoing disease and poison currently affecting her. Each successful save counts as two consecutive successful saving throws for the purpose of curing the affliction. Any failed saving throws do not result in additional damage or other effects. A non-alchemist who consumes a second purging mutagen in a 24-hour period is instead nauseated for 1 hour. When an alchemist drinks the mutagen, he can choose whether or not to also be affected by this discovery in addition to the mutagen's other effects.</p>
</>};
const _rag_doll_mutagen = {title: "Rag Doll Mutagen", jsx: <><h2 id="discovery-rag_doll_mutagen-rag-doll-mutagen">Rag Doll Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>(<Link to="/race/goblin">Goblin</Link> only) When the alchemist imbibes a mutagen, his body and bones become rubbery and easy to contort. The alchemist gains a bonus equal to his class level on Escape Artist checks, can <Link to="/misc/squeeze">squeeze</Link> through places as if he were one size category smaller, and can make a Reflex save (DC equal to 15 + 1 for every 10 feet fallen) to take half damage from falling. At 10th level, all falling damage is considered nonlethal damage, and the alchemist can squeeze through places as if he were two size categories smaller than his size while under the effects of this mutagen.</p>
</>};
const _splitting_mutagen = {title: "Splitting Mutagen", jsx: <><h2 id="discovery-splitting_mutagen-splitting-mutagen">Splitting Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-splitting_mutagen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>12th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Once per day while under the effects of his mutagen, the alchemist can split into two identical copies of himself as an immediate action after being damaged by a piercing or slashing weapon. Each copy has an ooze-like complexion, most often manifesting as a slimy sheen to his skin. The alchemist splits his current hit points evenly between the copies. The copies use the same statistics, share the same resources, and have identical equipment (except artifacts, which only one copy has). Similarly, if one of the copies expends a charge or daily use from a magic item that a copy has, the charge or daily use is expended from both copies. If one copy drops or gives away an item, the duplicate item disappears from the other copy as well. The two copies act independently and each one has a full set of actions. At the end of the alchemist's next turn, he selects one of the copies, which loses its ooze-like complexion as it becomes the alchemist; the other copy dissolves into a fine mist and dissipates. If one of the copies is destroyed before this happens, the remaining copy immediately becomes the alchemist, and he gains 1 permanent <Link to="/rule/negative_level">negative level</Link>. If both copies are destroyed simultaneously (such as from a <Link to="/spell/fireball">fireball</Link>), both copies collapse into formless goo; the alchemist can only be restored to life via <Link to="/spell/resurrection">resurrection</Link> or similarly powerful magic.</p>
</>};
const _celestial_poisons = {title: "Celestial Poisons", jsx: <><h2 id="discovery-celestial_poisons-celestial-poisons">Celestial Poisons</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-celestial_poisons--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist is able to infuse poisons with celestial power so they can affect evil creatures that are normally immune to poison. Any poison the alchemist administers to a weapon can affect undead and evil outsiders, bypassing their inherent immunities. Magical effects that negate poisons still apply. If a creature fails its save, the poison acts as normal, but may have no effect on the creature, depending on the effect of the poison (such as dealing <Link to="/rule/constitution_damage">Constitution damage</Link> to undead).</p>
</>};
const _concentrate_poison = {title: "Concentrate Poison", jsx: <><h2 id="discovery-concentrate_poison-concentrate-poison">Concentrate Poison</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The alchemist can combine two doses of the same poison to increase their effects. This requires two doses of the poison and 1 minute of concentration. When completed, the alchemist has one dose of poison. The poison's frequency is extended by 50% and the save DC increases by +2. This poison must be used within 1 hour of its creation or it is ruined.</p>
</>};
const _deadly_excretions = {title: "Deadly Excretions", jsx: <><h2 id="discovery-deadly_excretions-deadly-excretions">Deadly Excretions</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-deadly_excretions--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>8th level alchemist</li><li><Link to="/race/grippli">Grippli</Link></li><li>Toxic skin racial trait</li></ul></td></tr></tbody></table></ScrollContainer></div><p>When using his toxic skin ability, the alchemist can choose to excrete a Constitution poison instead of a Dexterity poison. This poison works the same as the normal grippli toxic skin poison except that a failed save deals 1 point of <Link to="/rule/constitution_damage">Constitution damage</Link>.</p>
</>};
const _designer_poison = {title: "Designer Poison", jsx: <><h2 id="discovery-designer_poison-designer-poison">Designer Poison</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>The alchemist can create special poisons that are more effective against certain creatures. When crafting a poison, the alchemist can choose a single creature type (and subtype, if appropriate) from the ranger's <Link to="/ability/favored_enemy">favored enemy</Link> list. Against creatures of the chosen type, the poison's saving throw DC is increased by 4. Against all other creatures, it is reduced by 2. The alchemist must choose the creature type and subtype (if appropriate) while crafting the poison and afterward cannot change this choice.</p>
</>};
const _elemental_destabilizers = {title: "Elemental Destabilizers", jsx: <><h2 id="discovery-elemental_destabilizers-elemental-destabilizers">Elemental Destabilizers</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-elemental_destabilizers--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist is able to concoct reactive chemical compounds that affect elementals like poisons. The alchemist can craft poisons that affect only outsiders with the elemental subtype, bypassing their inherent immunity. Magical effects that negate poisons still apply. If a creature fails its saving throw, the poison acts as normal, but it may have no effect on the creature depending on the effect of the poison (such as dealing fire damage to a <Link to="/monster/fire_elemental">fire elemental</Link>).</p>
</>};
const _enduring_toxin = {title: "Enduring Toxin", jsx: <><h2 id="discovery-enduring_toxin-enduring-toxin">Enduring Toxin</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-enduring_toxin--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist can alter the properties of a poison, causing it to persist longer in the victim's body. Altering a dose of poison in the way takes 1 hour, requires the expenditure of raw materials worth half the poison's market price, and exposes the alchemist to the poison, thereby affecting him if he is not immune. This doubles the poison's maximum duration.</p>
</>};
const _malignant_poison = {title: "Malignant Poison", jsx: <><h2 id="discovery-malignant_poison-malignant-poison">Malignant Poison</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-malignant_poison--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>10th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>As a full-round action, the alchemist can increase the save DC of any poison by 4 and increase its duration by 2 frequency increments (for example, <Link to="/eq-poison/large_scorpion_venom">large scorpion venom</Link> lasts 8 rounds instead of 6 and <Link to="/eq-poison/drow_poison">drow poison</Link> lasts 4 minutes instead of 2). Additionally, malignant poisons take effect immediately and do not have an onset time. This alchemical change lasts until the poison's extended duration ends or for a number of minutes equal to the alchemist's level, whichever comes first. After that, the poison reverts back to its original state.</p>
</>};
const _nauseating_flesh = {title: "Nauseating Flesh", jsx: <><h2 id="discovery-nauseating_flesh-nauseating-flesh">Nauseating Flesh</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-nauseating_flesh--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>12th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist's body is suffused with poison. Any creature that bites, engulfs, or swallows the alchemist must make a Fortitude saving throw or be <Link to="/misc/nauseated">nauseated</Link> for 1d4 rounds. The alchemist with this discovery does not suffer the effect of the poison of his own nauseating flesh.</p>
</>};
const _poison_conversion = {title: "Poison Conversion", jsx: <><h2 id="discovery-poison_conversion-poison-conversion">Poison Conversion</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-poison_conversion--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>By spending 1 minute, the alchemist can convert 1 dose of poison from its current type (contact, ingested, inhaled, or injury) to another type. For example, the alchemist can convert a dose of <Link to="/eq-poison/small_centipede_poison">Small centipede poison</Link> (an injury poison) to an inhaled poison. This process requires an <Link to="/misc/alchemy_lab">alchemy lab</Link>.</p>
</>};
const _precise_poison = {title: "Precise Poison", jsx: <><h2 id="discovery-precise_poison-precise-poison">Precise Poison</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex</Link><br/>The alchemist is adept at delivering poison to the most vulnerable areas of his targets. When the alchemist confirms a critical hit with a poisoned weapon, he increases the save DC of the poison by an amount equal to the weapon's critical multiplier.</p>
</>};
const _sticky_poison = {title: "Sticky Poison", jsx: <><h2 id="discovery-sticky_poison-sticky-poison">Sticky Poison</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-sticky_poison--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Any poison the alchemist creates is sticky - when the alchemist applies it to a weapon, the weapon remains poisoned for a number of strikes equal to the alchemist's Intelligence modifier.</p>
</>};
const _dilution = {title: "Dilution", jsx: <><h2 id="discovery-dilution-dilution">Dilution</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-dilution--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>12th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Once per day, the alchemist can dilute any one potion or elixir, creating two doses of the same potion from one. Diluting a potion costs a number of gp equal to one-quarter of the potion's market value. A potion that has been diluted cannot be diluted again. This discovery cannot be used to dilute extracts or mutagens.</p>
</>};
const _elixir_of_life = {title: "Elixir of Life", jsx: <><h2 id="discovery-elixir_of_life-elixir-of-life">Elixir of Life</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-elixir_of_life--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>16th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Once per day, the alchemist can brew an elixir of life. This special concoction costs 25,000 gp to create and takes 1 hour of work. An elixir of life, when administered by the alchemist who brewed it, restores life to a dead creature as per the spell <Link to="/spell/true_resurrection">true resurrection</Link>. Alternatively, the alchemist himself may drink the elixir of life, after which point he is immediately targeted with a <Link to="/spell/resurrection">resurrection</Link> spell the next time he is killed. Used in this manner, the effects of an elixir of life persist only for a number of days equal to the alchemist's Intelligence modifier; if he does not die before that time expires, the effects of the elixir of life end.</p>
</>};
const _enhance_potion = {title: "Enhance Potion", jsx: <><h2 id="discovery-enhance_potion-enhance-potion">Enhance Potion</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>A number of times per day equal to his Intelligence modifier, the alchemist can cause any potion he drinks to function at a caster level equal to his class level.</p>
</>};
const _extend_potion = {title: "Extend Potion", tree: ["Eternal Potion"], jsx: <><h2 id="discovery-extend_potion-extend-potion">Extend Potion</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>A number of times per day equal to his Intelligence modifier, the alchemist can cause any potion he drinks that does not have an instantaneous duration to function at twice its normal duration. This does not apply to extracts.</p>
</>};
const _eternal_potion = {title: "Eternal Potion", jsx: <><h2 id="discovery-eternal_potion-eternal-potion">Eternal Potion</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-eternal_potion--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>16th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/extend_potion">extend potion</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>If an alchemist drinks a potion that he extends, the effects of that potion become permanent until he chooses to make another potion effect permanent.</p>
</>};
const _lasting_tinctures = {title: "Lasting Tinctures", jsx: <><h2 id="discovery-lasting_tinctures-lasting-tinctures">Lasting Tinctures</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>The alchemist knows how to make <Link to="/main/equipment_alchemical">tinctures</Link> that last much longer than normal. The durations of the effects of any tinctures the alchemist brews using the Craft skill are doubled. When the alchemist uses this discovery to brew a longer-lasting tincture, the tincture imposes its normal penalties on the alchemist even if the alchemist has an ability that reduces tinctures' penalties (such as the substance tolerance ability of the <Link to="/arc-alchemist/fermenter">fermenter alchemist archetype</Link>). An alchemist with this discovery can brew tinctures with normal durations.</p>
</>};
const _air_lung = {title: "Air Lung", jsx: <><h2 id="discovery-air_lung-air-lung">Air Lung</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_123_the_flooded_cathedral">Pathfinder #123: The Flooded Cathedral</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-air_lung--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><Link to="/subtype/aquatic">Aquatic</Link> subtype</td></tr></tbody></table></ScrollContainer></div><p>An alchemist with this discovery has conditioned his body to adapt to life above water. He gains the <Link to="/umr/amphibious">amphibious</Link> special quality.</p>
</>};
const _alchemical_simulacrum = {title: "Alchemical Simulacrum", tree: ["Doppelganger Simulacrum","Greater Alchemical Simulacrum"], jsx: <><h2 id="discovery-alchemical_simulacrum-alchemical-simulacrum">Alchemical Simulacrum</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-alchemical_simulacrum--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist gains the ability to create a <Link to="/spell/lesser_simulacrum">lesser simulacrum</Link>. This works like the <em>lesser simulacrum</em> spell, except it costs 100 gp in alchemical materials per Hit Die of the simulacrum, requires 24 hours to grow, and decays into inert flesh rather than ice or snow if killed. The created simulacrum is a creature, not a supernatural effect.</p>
</>};
const _doppelganger_simulacrum = {title: "Doppelganger Simulacrum", jsx: <><h2 id="discovery-doppelganger_simulacrum-doppelganger-simulacrum">Doppelganger Simulacrum</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-doppelganger_simulacrum--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>10th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/alchemical_simulacrum">alchemical simulacrum</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist learns how to create a <Link to="/spell/simulacrum">simulacrum</Link>, a soulless duplicate, into which he can project his consciousness. As a full-round action, he may shift his consciousness from his current body to any one of his available doppelganger simulacra, which must be on the same plane as the alchemist. If killed in a simulacrum, he transfers to his own body automatically; if killed in his own body, he is dead. Unused simulacra (including his abandoned original body) appear to be lifeless corpses, though they do not decay. Creating a duplicate costs 1,000 gp in alchemical materials and requires 1 week to grow. The created simulacrum is a creature, not a supernatural effect.</p>
</>};
const _greater_alchemical_simulacrum = {title: "Greater Alchemical Simulacrum", jsx: <><h2 id="discovery-greater_alchemical_simulacrum-greater-alchemical-simulacrum">Greater Alchemical Simulacrum</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_alchemical_simulacrum--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>14th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/alchemical_simulacrum">alchemical simulacrum</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist gains the ability to create a simulacrum. This works like the <Link to="/spell/simulacrum">simulacrum</Link> spell, except it costs 100 gp in alchemical materials per Hit Die of the simulacrum, requires 24 hours to grow, and decays into inert flesh rather than ice or snow if killed. The created simulacrum is a creature, not a supernatural effect.</p>
</>};
const _alchemical_strike = {title: "Alchemical Strike", jsx: <><h2 id="discovery-alchemical_strike-alchemical-strike">Alchemical Strike</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 12</Link><br/>Gain <Link to="/feat/alchemical_strike">Alchemical Strike</Link> as a bonus feat. You do not need to meet its prerequisites.</p>
</>};
const _alchemical_zombie = {title: "Alchemical Zombie", tree: ["Boneshard Bomb"], jsx: <><h2 id="discovery-alchemical_zombie-alchemical-zombie">Alchemical Zombie</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-alchemical_zombie--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist gains the ability to animate a relatively complete corpse as an alchemy-powered zombie. This process takes 1 hour and costs 100 gp in alchemical reagents per HD of the corpse being animated; the dead creature gains the <Link to="/template/zombie">zombie template</Link>. Zombies that are created in this manner count as undead created by <Link to="/spell/animate_dead">animate dead</Link> for the purposes of determining how many undead the alchemist can control. The created zombie is a creature, not a supernatural effect.</p>
</>};
const _bitter_pill = {title: "Bitter Pill", jsx: <><h2 id="discovery-bitter_pill-bitter-pill">Bitter Pill</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness</Link><br/>The alchemist becomes bitter in flavor. Any creature that hits the bitter alchemist with a bite attack gains the <Link to="/misc/sickened">sickened</Link> condition for 1 round unless it succeeds at a Fortitude save (DC = 10 + half the alchemist's level + the alchemist's Constitution modifier). Any creature that swallows the alchemist whole gains the <Link to="/misc/nauseated">nauseated</Link> condition for 1 round unless it succeeds at a Fortitude save (same DC as above). If the alchemist is trapped in the creature's gullet and it becomes nauseated, the creature vomits him back out immediately as a free action at the start of the creature's turn; the alchemist lands <Link to="/rule/prone">prone</Link> adjacent to the creature.</p>
</>};
const _chameleon = {title: "Chameleon", jsx: <><h2 id="discovery-chameleon-chameleon">Chameleon</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide</Link><br/>An alchemist with this discovery can shift the colors of his skin and equipment to blend in with the surrounding terrain. He gains a +4 enhancement bonus on Stealth checks. At 10th level, the bonus on Stealth checks increases to +8.</p>
</>};
const _gills = {title: "Gills", jsx: <><h2 id="discovery-gills-gills">Gills</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_123_the_flooded_cathedral">Pathfinder #123: The Flooded Cathedral</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-gills--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>An alchemist with this discovery grows a set of gills that allow him to breathe water in addition to breathing air. When on land, the alchemist risks his gills drying out and must bathe his gills with 1/2 gallon of water every 24 hours he is out of the water or take 1 point of <Link to="/rule/constitution_damage">Constitution damage</Link> every hour thereafter.</p>
</>};
const _lingering_spirit = {title: "Lingering Spirit", jsx: <><h2 id="discovery-lingering_spirit-lingering-spirit">Lingering Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-lingering_spirit--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist is familiar enough with the ties between his body and spirit that he lingers at death's door far longer than a normal person. He treats his Constitution as 10 points higher than normal for the purpose of determining when hit point damage kills him (so an alchemist with a Constitution of 10 and this discovery dies at -20 hit points instead of -10). Reducing him to 0 Constitution or its equivalent (from ability damage, ability drain, Constitution penalties, and so on) makes him unconscious and comatose, but he is only killed after taking an additional 5 points of Constitution damage, drain, or penalty (in effect, the alchemist must be brought to -5 Constitution in order to be killed by these attacks).</p>
</>};
const _material_mastery = {title: "Material Mastery", jsx: <><h2 id="discovery-material_mastery-material-mastery">Material Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions</Link><br/>Your superior knowledge of the nature of matter enables you to ignore spell requirements more easily when crafting magic items. By expending an extract of the same school and level as a spell prerequisite when crafting a magic item, you take only a -2 penalty for ignoring that requirement, instead of -5.</p>
</>};
const _method_to_the_madness = {title: "Method to the Madness", jsx: <><h2 id="discovery-method_to_the_madness-method-to-the-madness">Method to the Madness</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-method_to_the_madness--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>The <Link to="/monster/derro">madness</Link> extraordinary ability</td></tr></tbody></table></ScrollContainer></div><p>The alchemist has learned to channel his madness into one of his alchemist class abilities. When the alchemist takes this discovery, he chooses one of either bombs or extracts. If he selects bombs, he uses his Charisma bonus in place of his Intelligence bonus when determining the bonus to damage and the saving throw DCs of his bombs. If the alchemist selects extracts, he uses his Charisma bonus in place of his Intelligence bonus to calculate bonus extracts per day. This discovery can be taken twice, allowing the alchemist to select both bombs and extracts.</p>
</>};
const _monstrous_graft = {title: "Monstrous Graft", jsx: <><h2 id="discovery-monstrous_graft-monstrous-graft">Monstrous Graft</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex</Link><br/>The alchemist can replace up to four of his own amputated limbs with those of a monstrous beast of the same size category. If the grafted limb is an arm, the alchemist gains either a climb speed of 15 feet or a claw or slam natural attack that deals 1d6 points of damage (1d4 for a Small alchemist). If the grafted limb is a leg, the alchemist gains one of the following benefits: a +5 bonus to land speed, a swim speed of 15 feet, or a +5 bonus on Acrobatics checks when jumping. For each limb the alchemist replaces in this manner, he takes a -2 penalty to Wisdom as he loses his sense of self. <Link to="/monster/derro">Derros</Link> are immune to this penalty.</p>
</>};
const _phantom_limb = {title: "Phantom Limb", jsx: <><h2 id="discovery-phantom_limb-phantom-limb">Phantom Limb</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-phantom_limb--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>8th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist can manifest a ghostly, incorporeal arm that juts out from his torso. This phantom limb does not grant the alchemist any extra attacks or actions per round, and it cannot hold or grab anything (including incorporeal objects). The alchemist may use his phantom limb to make a touch attack against a foe as a standard action, scraping away at the very fibers of the victim's soul. This attack deals 1d4 points of damage per alchemist level (Fortitude half). Creatures that are immune to incorporeal attacks are immune to this damage, but otherwise the damage bypasses all forms of damage reduction except DR/epic. The alchemist may suppress or activate this ability as a free action, and can use his phantom limb for a number of rounds per day equal to 3 + his Intelligence modifier (these rounds need not be consecutive).</p>
</>};
const _pheromones = {title: "Pheromones", jsx: <><h2 id="discovery-pheromones-pheromones">Pheromones</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness</Link><br/>The alchemist exudes an imperceptible musk that grants him a permanent +3 competence bonus on Bluff, Diplomacy, and Intimidate checks.</p>
</>};
const _preserve_organs = {title: "Preserve Organs", tree: ["Mummification"], jsx: <><h2 id="discovery-preserve_organs-preserve-organs">Preserve Organs</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>The alchemist learns how to preserve and protect his vital organs, reducing the chance of a mortal wound. When a critical hit or sneak attack is scored on the alchemist, there is a 25% chance that the critical hit or sneak attack is negated and damage is instead rolled normally. This does not stack with similar abilities that negate critical hits and sneak attacks (such as <Link to="/magic-enh/fortification">fortification</Link> armor). An alchemist can take this discovery up to three times; the effects stack, increasing this chance to 50% and then 75%.</p>
</>};
const _mummification = {title: "Mummification", jsx: <><h2 id="discovery-mummification-mummification">Mummification</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-mummification--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>10th level alchemist</li><li><strong>Discovery:</strong> <Link to="/discovery/preserve_organs">preserve organs</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist has mastered preserving flesh and applied this knowledge to his own body, turning himself into an undead-like creature. After learning this discovery, the alchemist must perform a 30-day regimen of a special diet, rigorous exercise, and drinking a mildly poisonous alchemical tea. At the end of this regimen, he falls unconscious for 24 hours, then awakens as a "living mummy." The alchemist's type does not change, but he becomes immune to cold, nonlethal damage, paralysis, and sleep.</p>
</>};
const _promethean_disciple = {title: "Promethean Disciple", jsx: <><h2 id="discovery-promethean_disciple-promethean-disciple">Promethean Disciple</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-promethean_disciple--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>An alchemist with this discovery learns how to craft constructs by way of alchemical research rather than arcane magic. The alchemist gains <Link to="/feat/craft_construct">Craft Construct</Link> as a bonus feat without needing to meet its requirements. The alchemist substitutes his number of ranks in Craft (alchemy) for his total caster level and must use Craft (alchemy) to create the construct. The DC to create the construct still increases for any necessary spells that the alchemist does not have access to. However, the alchemist can use extracts in place of spells as spell prerequisites.</p>
</>};
const _psychokinetic_tincture = {title: "Psychokinetic Tincture", jsx: <><h2 id="discovery-psychokinetic_tincture-psychokinetic-tincture">Psychokinetic Tincture</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-psychokinetic_tincture--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>Once per day, the alchemist can concoct a foul-tasting tincture that harnesses the power of the spirit. By drinking this tincture as a standard action, the alchemist can invite the latent spirits in the area to surround him. The alchemist can channel one spirit for every 4 alchemist levels he possesses. Each spirit channeled this way grants the alchemist a +1 deflection bonus to AC as the spirits whirl around his body. As a standard action, the alchemist can launch one of these spirits toward a target as a ranged touch attack. Launching a spirit this way reduces this discovery's deflection bonus to AC by 1. As a launched spirit passes through its target's body, it emits a terrible wail heard only in the target's mind, causing the target to become <Link to="/misc/frightened">frightened</Link> for 1 round per alchemist level (Will negates). This is a mind-affecting fear effect. A creature that successfully saves against the wail cannot be affected by this discovery again for 24 hours. The spirits whirl around the alchemist's body for 10 minutes per alchemist level, or until the alchemist has launched all of the spirits.</p>
</>};
const _ranged_baptism = {title: "Ranged Baptism", jsx: <><h2 id="discovery-ranged_baptism-ranged-baptism">Ranged Baptism</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-ranged_baptism--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>4th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>When the alchemist uses <Link to="/eq-weapon/holy_water">holy water</Link> as a splash weapon, any squares subject to its effects (including creatures affected by splash damage) or that contain creatures subject to its effects are also affected as if by <Link to="/spell/consecrate">consecrate</Link>, for a number of rounds equal to the alchemist's Intelligence modifier. Undead struck by holy water remain affected by the <em>consecrate</em> effect even if they leave the affected area.</p>
</>};
const _sleeper_agent = {title: "Sleeper Agent", jsx: <><h2 id="discovery-sleeper_agent-sleeper-agent">Sleeper Agent</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-sleeper_agent--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>12th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist learns how to create a sleeper agent, whom he releases back into its original society none the wiser. The alchemist can create a sleeper agent in a ritual that takes 1 minute; the target must be unconscious for the ritual's duration. At any time during the next year, as long as he is within 1 mile of the sleeper agent, the alchemist can activate the agent's programming. When the sleeper agent is activated, treat her as if she were the target of a <Link to="/spell/dominate_person">dominate person</Link> spell with a caster level equal to the alchemist's level at the time the sleeper agent was created. If the sleeper agent is killed or the <em>dominate person</em> effect's duration expires, the sleeper agent is permanently released from the alchemist's control. The alchemist can also release any sleeper agent as a free action. The alchemist can have one active sleeper agent for every 6 alchemist levels he possesses.</p>
</>};
const _spell_knowledge = {title: "Spell Knowledge", jsx: <><h2 id="discovery-spell_knowledge-spell-knowledge">Spell Knowledge</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions</Link><br/>Your studies into how all things are interconnected have taught you to cast a very limited number of spells. Select a single spell from the <Link to="/main/spells_sorcerer">sorcerer</Link>/<Link to="/main/wizard_spell">wizard spell list</Link> that is at least 2 levels lower than your highest-level extract known. You can prepare and cast this spell as an arcane spell. Preparing the spell uses up an extract slot 1 level higher than the spell's level. Your caster level is equal to your alchemist level, and your save DCs and <Link to="/rule/concentration">concentration</Link> checks are Intelligence-based. You're considered to have this spell on your spell list for purposes of prerequisites, <Link to="/misc/spell_completion">spell completion</Link> items, and <Link to="/misc/spell_trigger">spell trigger</Link> items. You may select this discovery more than once. Each time, it grants you access to another spell from the sorcerer/wizard spell list.</p>
</>};
const _spontaneous_healing = {title: "Spontaneous Healing", tree: ["Healing Touch"], jsx: <><h2 id="discovery-spontaneous_healing-spontaneous-healing">Spontaneous Healing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>The alchemist gains the ability to heal from wounds rapidly. As a free action once per round, he can heal 5 hit points as if he had the <Link to="/umr/fast_healing">fast healing</Link> ability. He can heal 5 hit points per day in this manner for every 2 alchemist levels he possesses. If the alchemist falls unconscious because of hit point damage and he still has healing available from this ability, the ability activates automatically each round until he is conscious again or the ability is depleted for the day.</p>
</>};
const _healing_touch = {title: "Healing Touch", jsx: <><h2 id="discovery-healing_touch-healing-touch">Healing Touch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-healing_touch--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>6th level alchemist</li><li><strong>Discovery or Class Ability:</strong> <Link to="/discovery/spontaneous_healing">spontaneous healing</Link></li></ul></td></tr></tbody></table></ScrollContainer></div><p>The alchemist gains the ability to heal other creatures. As a standard action, he may touch a creature and apply 1 round's effect of his spontaneous healing discovery to that creature; this counts toward his spontaneous healing limit for the day. The alchemist's daily limit for hit points healed by spontaneous healing increases to 5 &times; his alchemist level. This ability only functions if the target is the same type of creature (humanoid, undead, and so on) as the alchemist</p>
</>};
const _sunlight_acclimation = {title: "Sunlight Acclimation", jsx: <><h2 id="discovery-sunlight_acclimation-sunlight-acclimation">Sunlight Acclimation</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex</Link><br/>Time spent in the bright light of day has partially inured the alchemist to its effects. When the alchemist would normally take Constitution damage as a result of vulnerability to sunlight, he can attempt a DC 11 Fortitude saving throw to negate the effects. The DC of this saving throw increases by 1 for each hour after the first spent in sunlight within the last 24 hours.</p>
</>};
const _tentacle = {title: "Tentacle", jsx: <><h2 id="discovery-tentacle-tentacle">Tentacle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>The alchemist gains a prehensile, arm-length tentacle on his body. The tentacle is fully under his control and cannot be concealed except with magic or bulky clothing. The tentacle does not give the alchemist any extra attacks or actions per round, though he can use it to make a <Link to="/umr/tentacle_attack">tentacle attack</Link> (1d4 damage for a Medium alchemist, 1d3 damage for a Small one) with the <Link to="/umr/grab">grab</Link> ability. The tentacle can manipulate or hold items as well as the alchemist's original arms can (for example, allowing the alchemist to use one hand to wield a weapon, the tentacle to hold a potion, and the third hand to throw a bomb). Unlike an arm, the tentacle has no magic item slots.</p>
</>};
const _tumor_familiar = {title: "Tumor Familiar", jsx: <><h2 id="discovery-tumor_familiar-tumor-familiar">Tumor Familiar</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>The alchemist creates a Diminutive or Tiny tumor on his body, usually on his back or stomach. As a standard action, the alchemist can have the tumor detach itself from his body as a separate creature vaguely resembling a kind of animal suitable for a <Link to="/ability/familiar">familiar</Link> (bat, cat, and so on) and move about as if it were an independent creature. The tumor can reattach itself to the alchemist as a standard action. The tumor has all the abilities of the animal it resembles (for example, a bat-like tumor can fly) and <Link to="/sidekick/familiar">familiar abilities</Link> based on the alchemist's caster level (though some familiar abilities may be useless to an alchemist). The tumor acts as the alchemist's familiar whether attached or separated (providing a skill bonus, the <Link to="/feat/alertness">Alertness</Link> feat, and so on). When attached to the alchemist, the tumor has <Link to="/umr/fast_healing">fast healing</Link> 5. An alchemist's extracts and mutagens are considered spells for the purposes of familiar abilities like share spells and deliver touch spells. If a tumor familiar is lost or dies, it can be replaced 1 week later through a specialized procedure that costs 200 gp per alchemist level. The ritual takes 8 hours to complete.</p>
</>};
const _vestigial_arm = {title: "Vestigial Arm", tree: ["Parasitic Twin","Subsumed Spirit"], jsx: <><h2 id="discovery-vestigial_arm-vestigial-arm">Vestigial Arm</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link><br/>The alchemist gains a new arm (left or right) on his torso. The arm is fully under his control and cannot be concealed except with magic or bulky clothing. The arm does not give the alchemist any extra attacks or actions per round, though the arm can wield a weapon and make attacks as part of the alchemist's attack routine (using two-weapon fighting). The arm can manipulate or hold items as well as the alchemist's original arms (for example, allowing the alchemist to use one hand to wield a weapon, another hand to hold a potion, and the third hand to throw a bomb). The arm has its own "hand" and "ring" magic item slots (though the alchemist can still only wear two rings and two hand magic items at a time). An alchemist may take this discovery up to two times.</p>
</>};
const _parasitic_twin = {title: "Parasitic Twin", tree: ["Subsumed Spirit"], jsx: <><h2 id="discovery-parasitic_twin-parasitic-twin">Parasitic Twin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-parasitic_twin--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>Taken the <Link to="/discovery/vestigial_arm">vestigial arm</Link> discovery twice</td></tr></tbody></table></ScrollContainer></div><p>The alchemist's vestigial limbs are part of a parasitic twin on his torso, consisting of a head, a torso, and two arms (from the vestigial limb discovery). Normally, the twin is mostly recessed within the alchemist's body, with the visible arms acting like the vestigial arm discovery, though the alchemist can manifest or hide the twin as a standard action. The twin is helpless, fully subservient to the alchemist, and cannot be targeted or harmed. Once per day, if the alchemist succumbs to a mental effect that would make him unconscious, helpless, or not in control of his own actions (such as <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/feeblemind">feeblemind</Link>, or <Link to="/spell/hold_person">hold person</Link>), he can reroll his saving throw; success means the twin absorbs the effect and the alchemist can ignore it. Using this ability <Link to="/misc/sicken">sickens</Link> the alchemist for the duration of the absorbed effect (removing the effect from the twin ends the sickened condition), and he cannot use the twin's limbs during that time, though passive effects (such as from rings worn on the vestigial limbs) continue normally.</p>
</>};
const _subsumed_spirit = {title: "Subsumed Spirit", jsx: <><h2 id="discovery-subsumed_spirit-subsumed-spirit">Subsumed Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-subsumed_spirit--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/parasitic_twin">parasitic twin</Link></td></tr></tbody></table></ScrollContainer></div><p>As the alchemist grows in power, his parasitic twin laps up a portion of his soul, like a dog feeding on its master's scraps. The alchemist's parasitic twin can now manifest or hide within the alchemist's torso as a move action. As a standard action, the alchemist can cause his manifested twin to babble, driving listeners insane. All creatures without the insanity special ability (although see below) that are within 60 feet of the alchemist must succeed at a Will save or be affected by <Link to="/spell/confusion">confusion</Link> for 1 round per alchemist level. The alchemist can urge his parasitic twin to babble a number of times per day equal to 3 + the alchemist's Intelligence modifier. Creatures that successfully save can't be affected by this effect for 24 hours. The alchemist is immune to its sibling's babbling. This is a sonic, mind-affecting compulsion effect.</p>
<aside><p>This discovery was presented in a section on the <Link to="/monster/derro">Derro</Link> who have a special ability called <strong>Madness</strong>, which is referenced by a separate discovery (<Link to="/discovery/method_to_the_madness">method to the madness</Link>) in that same section. It is unclear if this discovery is supposed to be referring to that ability, rather than "insanity", which is possessed by the unrelated <Link to="/subtype/great_old_one">Great Old Ones</Link> and <Link to="/monster/warped_one">warped ones</Link>. Consult your GM if needed.</p>
</aside></>};
const _webbed_extremities = {title: "Webbed Extremities", jsx: <><h2 id="discovery-webbed_extremities-webbed-extremities">Webbed Extremities</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_123_the_flooded_cathedral">Pathfinder #123: The Flooded Cathedral</Link><br/>An alchemist with this discovery grows membranes between his fingers and toes, greatly improving his movement underwater. The alchemist gains a +4 alchemical bonus on Swim checks and can take 10 on a Swim check even if distracted or endangered while swimming.</p>
</>};
const _wet_coat = {title: "Wet Coat", jsx: <><h2 id="discovery-wet_coat-wet-coat">Wet Coat</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_123_the_flooded_cathedral">Pathfinder #123: The Flooded Cathedral</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-wet_coat--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><ul><li>4th level alchemist</li><li><Link to="/subtype/aquatic">Aquatic</Link> subtype and <Link to="/umr/water_dependency">water dependency</Link> special quality</li></ul></td></tr></tbody></table></ScrollContainer></div><p>An alchemist with this discovery has conditioned his body so that it never completely dries out when on land. He effectively becomes immune to any detrimental effects of his water dependency.</p>
</>};
const _wings = {title: "Wings", jsx: <><h2 id="discovery-wings-wings">Wings</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-wings--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>6th level alchemist</td></tr></tbody></table></ScrollContainer></div><p>The alchemist gains bat-like, bird-like, or insect-like functional wings, allowing him to fly as the <Link to="/spell/fly">fly</Link> spell for a number of minutes per day equal to his caster level. These minutes do not need to be consecutive, but they must be spent in 1-minute increments. An alchemist can select this discovery multiple times; each time he does so, he adds his caster level to the number of minutes per day that he can fly with the wings. This flight is an extraordinary ability.</p>
</>};
const _awakened_intellect = {title: "Awakened Intellect", topLink: ["Grand Discoveries","ability/grand_discoveries"], jsx: <><h2 id="discovery-awakened_intellect-awakened-intellect">Awakened Intellect</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The alchemist's constant exposure to strange chemicals has expanded his mind. His Intelligence score permanently increases by 2 points.</p>
</>};
const _greater_change_alignment = {title: "Greater Change Alignment", topLink: ["Grand Discoveries","ability/grand_discoveries"], jsx: <><h2 id="discovery-greater_change_alignment-greater-change-alignment-su">Greater Change Alignment (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-greater_change_alignment--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discoveries:</strong> <Link to="/discovery/change_alignment">change alignment</Link>, <Link to="/discovery/infusion">infusion</Link></td></tr></tbody></table></ScrollContainer></div><p>The effects of the alchemist's change alignment infusion become permanent and can only be reversed by a <Link to="/spell/wish">wish</Link> or <Link to="/spell/miracle">miracle</Link>. A permanent, forced change of alignment may be devastating, and some believe it is little better than zealous slavery or mind control. Others consider a good alignment brought about by any means but purity of heart an affront to freedom. This discovery remains controversial at best.</p>
</>};
const _eternal_youth = {title: "Eternal Youth", topLink: ["Grand Discoveries","ability/grand_discoveries"], jsx: <><h2 id="discovery-eternal_youth-eternal-youth">Eternal Youth</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The alchemist has discovered a cure for aging, and from this point forward he takes no penalty to his physical ability scores from <Link to="/rule/age">advanced age</Link>. If the alchemist is already taking such penalties, they are removed at this time.</p>
</>};
const _fast_healing = {title: "Fast Healing", topLink: ["Grand Discoveries","ability/grand_discoveries"], jsx: <><h2 id="discovery-fast_healing-fast-healing">Fast Healing</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The alchemist's flesh responds to damage with shocking speed - he gains <Link to="/umr/fast_healing">fast healing</Link> 5.</p>
</>};
const _philosophers_stone = {title: "Philosopher's Stone", topLink: ["Grand Discoveries","ability/grand_discoveries"], jsx: <><h2 id="discovery-philosophers_stone-philosophers-stone">Philosopher's Stone</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The alchemist learns how to create a <Link to="/magic-artifact/philosophers_stone">philosopher's stone</Link>, and can do so once per month at no cost. Creating a philosopher's stone takes 1 day of work.</p>
</>};
const _poison_touch = {title: "Poison Touch", topLink: ["Grand Discoveries","ability/grand_discoveries"], jsx: <><h2 id="discovery-poison_touch-poison-touch">Poison Touch</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The alchemist gains a poisonous touch, as if under the effects of a <Link to="/spell/poison">poison</Link> spell. He can suppress or activate this ability as a free action. The physical appearance of how the alchemist generates and delivers his poisonous touch varies from alchemist to alchemist.</p>
</>};
const _true_mutagen = {title: "True Mutagen", topLink: ["Grand Discoveries","ability/grand_discoveries"], jsx: <><h2 id="discovery-true_mutagen-true-mutagen">True Mutagen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>  </p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="discovery-true_mutagen--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><strong>Discovery:</strong> <Link to="/discovery/grand_mutagen">grand mutagen</Link></td></tr></tbody></table></ScrollContainer></div><p>The alchemist's mutagen now grants a +8 natural armor bonus and a +8 alchemical bonus to Strength, Dexterity, and Constitution. The alchemist takes a -2 penalty to his Intelligence, Wisdom, and Charisma as long as the mutagen persists.</p>
</>};
